{
  "name": "DroidScope Web Debugger",
  "description": "A browser-based Android debugging tool. Features simulated ADB connection, screen mirroring, stack inspection, environment detection, and AI-powered UI analysis using Gemini."
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export interface DeviceInfo {
  id: string;
  name: string;
  model: string;
  status: 'connected' | 'disconnected' | 'unauthorized';
  batteryLevel: number;
}

export interface AppStackInfo {
  packageName: string;
  activityName: string;
  taskId: number;
  isRunning: boolean;
}

export interface AppEnvInfo {
  environment: 'PRODUCTION' | 'STAGING' | 'DEVELOPMENT' | 'UNKNOWN';
  versionCode: number;
  versionName: string;
  debuggable: boolean;
}

export interface H5Info {
  currentUrl: string | null;
  pageTitle: string | null;
  userAgent: string;
}

export interface LayoutNode {
  id: string;
  class: string;
  bounds: string; // "[x,y][w,h]"
  children?: LayoutNode[];
}

export enum LogLevel {
  INFO = 'INFO',
  WARN = 'WARN',
  ERROR = 'ERROR',
  DEBUG = 'DEBUG'
}

export interface LogEntry {
  timestamp: string;
  level: LogLevel;
  tag: string;
  message: string;
}

import { DeviceInfo, AppStackInfo, AppEnvInfo, H5Info, LayoutNode, LogEntry, LogLevel } from '../types';

/**
 * NOTE: In a real-world scenario, this service would use the 'ya-webadb' library
 * to communicate with the Android device via the WebUSB API.
 * 
 * Since we cannot bundle large WASM/ADB libraries in this generation, 
 * this service simulates the ADB protocol responses for demonstration purposes.
 */

class AdbService {
  private connected: boolean = false;
  private mockInterval: number | null = null;

  async connect(): Promise<DeviceInfo> {
    // Simulate WebUSB device selection
    return new Promise((resolve) => {
      setTimeout(() => {
        this.connected = true;
        resolve({
          id: 'emulator-5554',
          name: 'Pixel 7 Pro',
          model: 'Google Pixel 7 Pro',
          status: 'connected',
          batteryLevel: 87
        });
      }, 1000);
    });
  }

  async disconnect(): Promise<void> {
    this.connected = false;
    if (this.mockInterval) clearInterval(this.mockInterval);
  }

  async getTopActivity(): Promise<AppStackInfo> {
    // Command: adb shell dumpsys activity activities | grep mResumedActivity
    await this.simulateDelay(300);
    return {
      packageName: 'com.example.android.myapp',
      activityName: 'com.example.android.myapp.MainActivity',
      taskId: 124,
      isRunning: true,
    };
  }

  async getEnvironment(): Promise<AppEnvInfo> {
    // Command: adb shell getprop | grep app.env
    await this.simulateDelay(200);
    // Simulating a random toggle between envs for demo
    const isStaging = Math.random() > 0.5;
    return {
      environment: isStaging ? 'STAGING' : 'PRODUCTION',
      versionCode: 10045,
      versionName: '2.4.5-beta',
      debuggable: true,
    };
  }

  async getH5Info(): Promise<H5Info> {
    // Command: Mocking WebView inspection
    await this.simulateDelay(400);
    return {
      currentUrl: 'https://m.example.com/promo/summer-sale?deviceId=xyz',
      pageTitle: 'Summer Sale 2024',
      userAgent: 'Mozilla/5.0 (Linux; Android 13; Pixel 7) AppleWebKit/537.36...',
    };
  }

  async getLayoutHierarchy(): Promise<LayoutNode> {
    // Command: adb shell uiautomator dump
    await this.simulateDelay(800);
    return {
      id: 'root',
      class: 'FrameLayout',
      bounds: '[0,0][1440,3120]',
      children: [
        {
          id: 'content',
          class: 'LinearLayout',
          bounds: '[0,100][1440,3120]',
          children: [
            { id: 'toolbar', class: 'Toolbar', bounds: '[0,100][1440,300]' },
            { id: 'webview', class: 'WebView', bounds: '[0,300][1440,2800]' },
            { id: 'fab', class: 'FloatingActionButton', bounds: '[1200,2600][1350,2750]' }
          ]
        }
      ]
    };
  }

  // Simulates a stream of logs
  subscribeLogs(callback: (log: LogEntry) => void): () => void {
    const interval = window.setInterval(() => {
      if (!this.connected) return;
      const types = [LogLevel.INFO, LogLevel.DEBUG, LogLevel.WARN];
      const type = types[Math.floor(Math.random() * types.length)];
      const tags = ['Network', 'ViewRoot', 'ActivityManager', 'WebView'];

      callback({
        timestamp: new Date().toISOString().split('T')[1].slice(0, 12),
        level: type,
        tag: tags[Math.floor(Math.random() * tags.length)],
        message: `Simulated log message content [${Math.random().toString(36).substring(7)}]`
      });
    }, 2000);

    return () => clearInterval(interval);
  }

  // Returns a base64 string of a fake screenshot
  async captureScreen(): Promise<string> {
    await this.simulateDelay(500);
    // This returns a placeholder image URL for the purpose of the demo
    // In a real app, this would be raw binary data converted to base64
    return "https://picsum.photos/400/800"; 
  }

  private simulateDelay(ms: number) {
    return new Promise(resolve => setTimeout(resolve, ms));
  }
}

export const adbService = new AdbService();

import { GoogleGenAI } from "@google/genai";

// Note: In a production app, never expose keys in client-side code if not guarded by authentication/proxy.
// We assume process.env.API_KEY is available as per instructions.

export const analyzeScreenWithGemini = async (base64Image: string, promptText: string) => {
  if (!process.env.API_KEY) {
    throw new Error("API Key not found in environment variables");
  }

  try {
    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

    // Convert the image data to the format expected by the SDK
    // If base64Image is a data URL (starts with "data:image/..."), strip the header
    let rawBase64 = base64Image;
    if (base64Image.includes(',')) {
      rawBase64 = base64Image.split(',')[1];
    }

    // Since our mock returns a URL (picsum), we can't actually send that URL to Gemini for "inlineData".
    // For this specific DEMO code, if the URL is http based, we will just send text.
    // If it were real base64, we would send the image.

    // IMPORTANT: For the sake of the requested functional code using Gemini:
    // We will fetch the image as blob, convert to base64 to simulate the real workflow.

    let parts: any[] = [{ text: promptText }];

    if (base64Image.startsWith('http')) {
        try {
            const response = await fetch(base64Image);
            const blob = await response.blob();
            const buffer = await blob.arrayBuffer();
            const bytes = new Uint8Array(buffer);
            let binary = '';
            const len = bytes.byteLength;
            for (let i = 0; i < len; i++) {
                binary += String.fromCharCode(bytes[i]);
            }
            rawBase64 = btoa(binary);

            parts.push({
                inlineData: {
                    mimeType: 'image/jpeg',
                    data: rawBase64
                }
            });
        } catch (e) {
            console.warn("Could not fetch placeholder image for Gemini analysis, falling back to text only.");
            parts[0].text = promptText + " (Note: Image fetch failed, analyze based on context only)";
        }
    } else {
         parts.push({
            inlineData: {
                mimeType: 'image/png',
                data: rawBase64
            }
        });
    }

    const response = await ai.models.generateContent({
      model: 'gemini-2.5-flash-image',
      contents: {
        parts: parts
      },
      config: {
          systemInstruction: "You are an expert Android Developer and UI/UX Designer. Analyze the provided screenshot for layout bugs, text visibility, and view hierarchy issues."
      }
    });

    return response.text;

  } catch (error) {
    console.error("Gemini Analysis Failed:", error);
    throw error;
  }
};

import React, { useEffect, useRef, useState } from 'react';
import { adbService } from '../services/adbService';
import { analyzeScreenWithGemini } from '../services/geminiService';
import { RefreshCw, Smartphone, Sparkles, Loader2, Camera } from 'lucide-react';

interface ScreenMirrorProps {
  connected: boolean;
}

export const ScreenMirror: React.FC<ScreenMirrorProps> = ({ connected }) => {
  const [imageUrl, setImageUrl] = useState<string | null>(null);
  const [analyzing, setAnalyzing] = useState(false);
  const [analysisResult, setAnalysisResult] = useState<string | null>(null);
  const [lastRefreshed, setLastRefreshed] = useState<Date>(new Date());

  const refreshScreen = async () => {
    if (!connected) return;
    try {
      const url = await adbService.captureScreen();
      // Add timestamp to force reload image if it's the same URL
      setImageUrl(`${url}?t=${new Date().getTime()}`);
      setLastRefreshed(new Date());
    } catch (e) {
      console.error("Failed to capture screen", e);
    }
  };

  useEffect(() => {
    let interval: number;
    if (connected) {
      refreshScreen();
      // Auto-refresh every 2 seconds to simulate low-fps mirroring
      interval = window.setInterval(refreshScreen, 2000);
    } else {
      setImageUrl(null);
      setAnalysisResult(null);
    }
    return () => clearInterval(interval);
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [connected]);

  const handleGeminiAnalyze = async () => {
    if (!imageUrl || analyzing) return;
    setAnalyzing(true);
    setAnalysisResult(null);
    try {
      // Pass the current image URL (which mimics base64 in our service)
      const result = await analyzeScreenWithGemini(imageUrl, "Identify the UI elements in this screen. Are there any potential layout issues or color contrast problems for accessibility?");
      setAnalysisResult(result || "No response from AI.");
    } catch (error) {
      setAnalysisResult("Failed to analyze screen. Ensure API Key is set.");
    } finally {
      setAnalyzing(false);
    }
  };

  return (
    <div className="flex flex-col h-full bg-slate-900 rounded-xl border border-slate-800 overflow-hidden shadow-lg">
      <div className="flex items-center justify-between px-4 py-3 bg-slate-850 border-b border-slate-800">
        <h3 className="text-sm font-semibold text-slate-300 flex items-center gap-2">
          <Smartphone size={16} className="text-cyan-400" />
          Device Screen
        </h3>
        <div className="flex gap-2">
          <button 
            onClick={refreshScreen}
            disabled={!connected}
            className="p-1.5 hover:bg-slate-700 rounded-md transition-colors text-slate-400 hover:text-white"
            title="Refresh Screenshot"
          >
            <Camera size={16} />
          </button>
           <button 
            onClick={handleGeminiAnalyze}
            disabled={!connected || !imageUrl || analyzing}
            className={`flex items-center gap-2 px-3 py-1.5 text-xs font-medium rounded-md transition-all ${
              analyzing 
                ? 'bg-purple-900/50 text-purple-200 cursor-not-allowed' 
                : 'bg-gradient-to-r from-indigo-600 to-purple-600 hover:from-indigo-500 hover:to-purple-500 text-white shadow-lg shadow-purple-900/20'
            }`}
          >
            {analyzing ? <Loader2 size={12} className="animate-spin" /> : <Sparkles size={12} />}
            {analyzing ? 'Thinking...' : 'AI Analyze'}
          </button>
        </div>
      </div>

      <div className="relative flex-1 bg-slate-950 flex items-center justify-center p-4 overflow-y-auto">
        {!connected ? (
          <div className="text-center text-slate-600">
            <Smartphone size={48} className="mx-auto mb-2 opacity-20" />
            <p className="text-sm">Device Disconnected</p>
          </div>
        ) : imageUrl ? (
          <div className="relative border-[8px] border-slate-800 rounded-[2rem] overflow-hidden shadow-2xl max-h-full">
            <img src={imageUrl} alt="Device Screen" className="max-h-[600px] w-auto object-contain" />

            {/* Overlay simulation */}
            <div className="absolute top-0 left-0 w-full h-6 bg-black/40 backdrop-blur-[2px] z-10"></div>
          </div>
        ) : (
          <div className="flex flex-col items-center text-slate-500">
            <RefreshCw size={24} className="animate-spin mb-2" />
            <span className="text-xs">Syncing Display...</span>
          </div>
        )}
      </div>

      {analysisResult && (
        <div className="p-4 bg-slate-900 border-t border-slate-800 max-h-48 overflow-y-auto">
            <h4 className="text-xs font-bold text-purple-400 mb-1 flex items-center gap-1">
                <Sparkles size={10} /> Gemini Analysis
            </h4>
            <p className="text-xs text-slate-300 leading-relaxed whitespace-pre-wrap font-mono">
                {analysisResult}
            </p>
        </div>
      )}

      <div className="px-3 py-1 bg-slate-900 text-[10px] text-slate-600 border-t border-slate-800 flex justify-between">
         <span>1080x2400 | 420dpi</span>
         <span>Synced: {lastRefreshed.toLocaleTimeString()}</span>
      </div>
    </div>
  );
};

import React from 'react';
import { LucideIcon } from 'lucide-react';

interface InfoPanelProps {
  title: string;
  icon: LucideIcon;
  loading?: boolean;
  children: React.ReactNode;
  action?: React.ReactNode;
}

export const InfoPanel: React.FC<InfoPanelProps> = ({ title, icon: Icon, loading, children, action }) => {
  return (
    <div className="bg-slate-900 rounded-xl border border-slate-800 shadow-md flex flex-col h-full">
      <div className="flex items-center justify-between px-4 py-3 border-b border-slate-800 bg-slate-850/50">
        <h3 className="text-sm font-semibold text-slate-300 flex items-center gap-2">
          <Icon size={16} className="text-cyan-500" />
          {title}
        </h3>
        {action && <div>{action}</div>}
      </div>
      <div className="p-4 flex-1 overflow-auto">
        {loading ? (
          <div className="h-full flex items-center justify-center">
             <div className="w-4 h-4 border-2 border-slate-600 border-t-cyan-400 rounded-full animate-spin"></div>
          </div>
        ) : (
          children
        )}
      </div>
    </div>
  );
};

import React, { useState, useEffect, useCallback } from 'react';
import { Activity, Box, Layers, Globe, Terminal, Cpu, Usb, AlertCircle, RefreshCw, Smartphone } from 'lucide-react';
import { adbService } from './services/adbService';
import { DeviceInfo, AppStackInfo, AppEnvInfo, H5Info, LogEntry, LayoutNode } from './types';
import { ScreenMirror } from './components/ScreenMirror';
import { InfoPanel } from './components/InfoPanel';

const App: React.FC = () => {
  const [device, setDevice] = useState<DeviceInfo | null>(null);
  const [connecting, setConnecting] = useState(false);
  const [activeTab, setActiveTab] = useState<'stack' | 'layout' | 'logs'>('stack');

  // Data States
  const [stackInfo, setStackInfo] = useState<AppStackInfo | null>(null);
  const [envInfo, setEnvInfo] = useState<AppEnvInfo | null>(null);
  const [h5Info, setH5Info] = useState<H5Info | null>(null);
  const [layout, setLayout] = useState<LayoutNode | null>(null);
  const [logs, setLogs] = useState<LogEntry[]>([]);
  const [loadingData, setLoadingData] = useState(false);

  const handleConnect = async () => {
    setConnecting(true);
    try {
      const dev = await adbService.connect();
      setDevice(dev);
      // Auto fetch data on connect
      fetchDeviceData();
    } catch (err) {
      console.error("Failed to connect", err);
    } finally {
      setConnecting(false);
    }
  };

  const handleDisconnect = async () => {
    await adbService.disconnect();
    setDevice(null);
    setStackInfo(null);
    setEnvInfo(null);
    setH5Info(null);
    setLogs([]);
  };

  const fetchDeviceData = useCallback(async () => {
    if (!device) return;
    setLoadingData(true);
    try {
        const [stack, env, h5, layoutData] = await Promise.all([
            adbService.getTopActivity(),
            adbService.getEnvironment(),
            adbService.getH5Info(),
            adbService.getLayoutHierarchy()
        ]);
        setStackInfo(stack);
        setEnvInfo(env);
        setH5Info(h5);
        setLayout(layoutData);
    } catch (e) {
        console.error("Error fetching data", e);
    } finally {
        setLoadingData(false);
    }
  }, [device]);

  useEffect(() => {
    if (device) {
      // Poll data every 5 seconds
      const poll = setInterval(fetchDeviceData, 5000);

      // Subscribe to logs
      const unsubscribe = adbService.subscribeLogs((log) => {
        setLogs(prev => [log, ...prev].slice(0, 100)); // Keep last 100 logs
      });

      return () => {
        clearInterval(poll);
        unsubscribe();
      };
    }
  }, [device, fetchDeviceData]);

  return (
    <div className="min-h-screen bg-slate-950 text-slate-200 flex flex-col font-sans">
      {/* Header */}
      <header className="h-16 bg-slate-900 border-b border-slate-800 flex items-center justify-between px-6 z-10 shrink-0">
        <div className="flex items-center gap-3">
          <div className="w-8 h-8 rounded-lg bg-cyan-500/10 flex items-center justify-center border border-cyan-500/20">
            <Cpu size={20} className="text-cyan-400" />
          </div>
          <h1 className="text-lg font-bold tracking-tight text-white">Droid<span className="text-cyan-400">Scope</span></h1>
        </div>

        <div className="flex items-center gap-4">
          {device ? (
            <div className="flex items-center gap-4 bg-slate-800/50 px-4 py-1.5 rounded-full border border-slate-700">
              <div className="flex flex-col items-end leading-none">
                <span className="text-xs font-medium text-slate-200">{device.name}</span>
                <span className="text-[10px] text-green-400 uppercase tracking-wider">{device.status} • {device.batteryLevel}%</span>
              </div>
              <button 
                onClick={handleDisconnect}
                className="p-1 hover:bg-slate-700 rounded-full transition-colors text-slate-400 hover:text-red-400"
              >
                <AlertCircle size={16} />
              </button>
            </div>
          ) : (
            <button 
              onClick={handleConnect}
              disabled={connecting}
              className="flex items-center gap-2 bg-cyan-600 hover:bg-cyan-500 text-white px-4 py-2 rounded-lg text-sm font-medium transition-colors shadow-lg shadow-cyan-900/20 disabled:opacity-50"
            >
              {connecting ? <RefreshCw className="animate-spin" size={16} /> : <Usb size={16} />}
              Connect USB Device
            </button>
          )}
        </div>
      </header>

      {/* Main Content */}
      <main className="flex-1 p-6 grid grid-cols-1 lg:grid-cols-12 gap-6 overflow-hidden">

        {/* Left Column: Screen Mirror */}
        <div className="lg:col-span-4 h-full flex flex-col min-h-[500px]">
           <ScreenMirror connected={!!device} />
        </div>

        {/* Right Column: Information Grid */}
        <div className="lg:col-span-8 h-full flex flex-col gap-6 overflow-hidden">

          {/* Top Row: Info Panels */}
          <div className="grid grid-cols-1 md:grid-cols-3 gap-6 shrink-0 h-64">

            <InfoPanel title="Top Activity" icon={Layers} loading={loadingData}>
              {stackInfo ? (
                <div className="space-y-4">
                  <div>
                    <span className="text-[10px] uppercase text-slate-500 font-bold tracking-wider">Activity</span>
                    <p className="text-sm font-mono text-cyan-300 break-all">{stackInfo.activityName.split('.').pop()}</p>
                  </div>
                  <div>
                    <span className="text-[10px] uppercase text-slate-500 font-bold tracking-wider">Package</span>
                    <p className="text-xs text-slate-400 break-all">{stackInfo.packageName}</p>
                  </div>
                  <div className="flex gap-2">
                     <span className={`text-[10px] px-2 py-0.5 rounded border ${stackInfo.isRunning ? 'border-green-800 bg-green-900/30 text-green-400' : 'border-red-800 bg-red-900/30 text-red-400'}`}>
                       {stackInfo.isRunning ? 'RESUMED' : 'PAUSED'}
                     </span>
                     <span className="text-[10px] px-2 py-0.5 rounded border border-slate-700 bg-slate-800 text-slate-400">
                       Task #{stackInfo.taskId}
                     </span>
                  </div>
                </div>
              ) : (
                <div className="h-full flex flex-col items-center justify-center text-slate-600">
                    <Layers size={24} className="mb-2 opacity-30" />
                    <span className="text-xs">No activity data</span>
                </div>
              )}
            </InfoPanel>

            <InfoPanel title="Environment" icon={Box} loading={loadingData}>
              {envInfo ? (
                <div className="space-y-4">
                  <div className="flex flex-col items-center justify-center py-2">
                    <span className={`text-xl font-black tracking-widest ${
                      envInfo.environment === 'PRODUCTION' 
                        ? 'text-red-400 drop-shadow-[0_0_8px_rgba(248,113,113,0.3)]' 
                        : envInfo.environment === 'STAGING'
                        ? 'text-yellow-400 drop-shadow-[0_0_8px_rgba(250,204,21,0.3)]'
                        : 'text-green-400'
                    }`}>
                      {envInfo.environment}
                    </span>
                  </div>
                  <div className="grid grid-cols-2 gap-2 text-xs">
                    <div className="bg-slate-950 p-2 rounded border border-slate-800">
                      <span className="block text-[10px] text-slate-500">Version</span>
                      <span className="text-slate-300 font-mono">{envInfo.versionName}</span>
                    </div>
                    <div className="bg-slate-950 p-2 rounded border border-slate-800">
                      <span className="block text-[10px] text-slate-500">Build</span>
                      <span className="text-slate-300 font-mono">{envInfo.versionCode}</span>
                    </div>
                  </div>
                </div>
              ) : (
                <div className="h-full flex flex-col items-center justify-center text-slate-600">
                   <Box size={24} className="mb-2 opacity-30" />
                   <span className="text-xs">Unknown Env</span>
                </div>
              )}
            </InfoPanel>

            <InfoPanel title="WebView H5" icon={Globe} loading={loadingData}>
               {h5Info && h5Info.currentUrl ? (
                <div className="space-y-3">
                  <div>
                    <span className="text-[10px] uppercase text-slate-500 font-bold tracking-wider">Page Title</span>
                    <p className="text-sm font-medium text-slate-200 line-clamp-1">{h5Info.pageTitle}</p>
                  </div>
                  <div>
                    <span className="text-[10px] uppercase text-slate-500 font-bold tracking-wider">URL</span>
                    <div className="p-2 bg-slate-950 rounded border border-slate-800 mt-1">
                      <p className="text-xs font-mono text-cyan-300 break-all line-clamp-3 leading-relaxed">
                        {h5Info.currentUrl}
                      </p>
                    </div>
                  </div>
                  <a 
                    href={h5Info.currentUrl} 
                    target="_blank" 
                    rel="noopener noreferrer"
                    className="text-[10px] text-cyan-500 hover:text-cyan-400 hover:underline flex items-center gap-1 justify-end"
                  >
                    Open in Browser &rarr;
                  </a>
                </div>
               ) : (
                <div className="h-full flex flex-col items-center justify-center text-slate-600">
                   <Globe size={24} className="mb-2 opacity-30" />
                   <span className="text-xs">No WebView Detected</span>
                </div>
               )}
            </InfoPanel>

          </div>

          {/* Bottom Row: Tabs (Layout / Logs) */}
          <div className="flex-1 min-h-0 bg-slate-900 rounded-xl border border-slate-800 shadow-md flex flex-col">
            <div className="flex border-b border-slate-800 px-2">
              <button 
                onClick={() => setActiveTab('stack')}
                className={`px-4 py-3 text-xs font-medium border-b-2 transition-colors flex items-center gap-2 ${activeTab === 'stack' ? 'border-cyan-500 text-cyan-400' : 'border-transparent text-slate-500 hover:text-slate-300'}`}
              >
                <Layers size={14} /> Layout Tree
              </button>
              <button 
                onClick={() => setActiveTab('logs')}
                className={`px-4 py-3 text-xs font-medium border-b-2 transition-colors flex items-center gap-2 ${activeTab === 'logs' ? 'border-cyan-500 text-cyan-400' : 'border-transparent text-slate-500 hover:text-slate-300'}`}
              >
                <Terminal size={14} /> Logcat Stream
              </button>
            </div>

            <div className="flex-1 overflow-auto p-4 font-mono text-xs">
               {activeTab === 'logs' ? (
                 <div className="space-y-1">
                   {logs.length === 0 && <span className="text-slate-600 italic">Waiting for logs...</span>}
                   {logs.map((log, i) => (
                     <div key={i} className="flex gap-2 hover:bg-slate-800/50 p-0.5 rounded cursor-default">
                       <span className="text-slate-500 shrink-0 select-none">{log.timestamp}</span>
                       <span className={`shrink-0 w-12 font-bold ${
                         log.level === 'ERROR' ? 'text-red-500' : 
                         log.level === 'WARN' ? 'text-yellow-500' : 
                         log.level === 'DEBUG' ? 'text-blue-500' : 'text-slate-400'
                       }`}>{log.level}</span>
                       <span className="text-purple-400 shrink-0 w-32 truncate" title={log.tag}>{log.tag}</span>
                       <span className="text-slate-300">{log.message}</span>
                     </div>
                   ))}
                 </div>
               ) : (
                 <div className="text-slate-300">
                    {layout ? (
                      <pre className="text-xs leading-relaxed text-green-300">
                        {JSON.stringify(layout, null, 2)}
                      </pre>
                    ) : (
                      <div className="flex flex-col items-center justify-center h-32 text-slate-600">
                         <span>Layout hierarchy not captured</span>
                      </div>
                    )}
                 </div>
               )}
            </div>
          </div>
        </div>
      </main>
    </div>
  );
};

