  const [logs, setLogs] = useState<LogEntry[]>([]);
  const [loadingData, setLoadingData] = useState(false);

  const handleConnect = async () => {
    setConnecting(true);
    try {
      const dev = await adbService.connect();
      setDevice(dev);
      // Auto fetch data on connect
      fetchDeviceData();
    } catch (err) {
      console.error("Failed to connect", err);
    } finally {
      setConnecting(false);
    }
  };

  // Attempt auto-connect on mount
  useEffect(() => {
    const autoConnect = async () => {
      // Check if we have paired devices (simulated WebUSB permission check)
      const paired = await adbService.getPairedDevices();
      if (paired.length > 0 && !device && !connecting) {
        console.log("Auto-connecting to detected device:", paired[0].name);
        handleConnect();
      }
    };
    autoConnect();
  }, []);

  const handleDisconnect = async () => {
    await adbService.disconnect();
    setDevice(null);
    setStackInfo(null);
    setEnvInfo(null);
