{
  "name": "DroidScope Web Debugger",
  "description": "A browser-based Android debugging tool. Features simulated ADB connection, screen mirroring, stack inspection, environment detection, and AI-powered UI analysis using Gemini.",
  "requestFramePermissions": [
    "usb"
  ]
}

import { DeviceInfo, AppStackInfo, AppEnvInfo, H5Info, LayoutNode, LogEntry, LogLevel } from '../types';

// --- WebUSB Type Definitions ---
interface USBDevice {
  usbVersionMajor: number;
  usbVersionMinor: number;
  usbVersionSubminor: number;
  deviceClass: number;
  deviceSubclass: number;
  deviceProtocol: number;
  vendorId: number;
  productId: number;
  deviceVersionMajor: number;
  deviceVersionMinor: number;
  deviceVersionSubminor: number;
  manufacturerName?: string;
  productName?: string;
  serialNumber?: string;
  configuration: USBConfiguration | null;
  configurations: USBConfiguration[];
  opened: boolean;
  open(): Promise<void>;
  close(): Promise<void>;
  selectConfiguration(configurationValue: number): Promise<void>;
  claimInterface(interfaceNumber: number): Promise<void>;
  releaseInterface(interfaceNumber: number): Promise<void>;
  selectAlternateInterface(interfaceNumber: number, alternateSetting: number): Promise<void>;
  controlTransferIn(setup: USBControlTransferParameters, length: number): Promise<USBInTransferResult>;
  controlTransferOut(setup: USBControlTransferParameters, data?: BufferSource): Promise<USBOutTransferResult>;
  clearHalt(direction: USBDirection, endpointNumber: number): Promise<void>;
  transferIn(endpointNumber: number, length: number): Promise<USBInTransferResult>;
  transferOut(endpointNumber: number, data: BufferSource): Promise<USBOutTransferResult>;
  isochronousTransferIn(endpointNumber: number, packetLengths: number[]): Promise<USBIsochronousInTransferResult>;
  isochronousTransferOut(endpointNumber: number, data: BufferSource, packetLengths: number[]): Promise<USBIsochronousOutTransferResult>;
  reset(): Promise<void>;
}

interface USBConfiguration {
  configurationValue: number;
  configurationName?: string;
  interfaces: USBInterface[];
}

interface USBInterface {
  interfaceNumber: number;
  alternate: USBAlternateInterface;
  alternates: USBAlternateInterface[];
  claimed: boolean;
}

interface USBAlternateInterface {
  alternateSetting: number;
  interfaceClass: number;
  interfaceSubclass: number;
  interfaceProtocol: number;
  interfaceName?: string;
  endpoints: USBEndpoint[];
}

interface USBEndpoint {
  endpointNumber: number;
  direction: USBDirection;
  type: USBEndpointType;
  packetSize: number;
}

type USBDirection = "in" | "out";
type USBEndpointType = "bulk" | "interrupt" | "isochronous";

interface USBControlTransferParameters {
  requestType: "standard" | "class" | "vendor";
  recipient: "device" | "interface" | "endpoint" | "other";
  request: number;
  value: number;
  index: number;
}

interface USBInTransferResult {
  data?: DataView;
  status: "ok" | "stall" | "babble";
}

interface USBOutTransferResult {
  bytesWritten: number;
  status: "ok" | "stall";
}

interface USBIsochronousInTransferResult {
  data?: DataView;
  packets: USBIsochronousInTransferPacket[];
}

interface USBIsochronousInTransferPacket {
  data?: DataView;
  status: "ok" | "stall" | "babble";
}

interface USBIsochronousOutTransferResult {
  packets: USBIsochronousOutTransferPacket[];
}

interface USBIsochronousOutTransferPacket {
  bytesWritten: number;
  status: "ok" | "stall";
}

interface USBManager extends EventTarget {
  onconnect: ((this: USBManager, ev: USBConnectionEvent) => any) | null;
  ondisconnect: ((this: USBManager, ev: USBConnectionEvent) => any) | null;
  getDevices(): Promise<USBDevice[]>;
  requestDevice(options?: USBDeviceRequestOptions): Promise<USBDevice>;
}

interface USBConnectionEvent extends Event {
  device: USBDevice;
}

interface USBDeviceRequestOptions {
  filters: USBDeviceFilter[];
}

interface USBDeviceFilter {
  vendorId?: number;
  productId?: number;
  classCode?: number;
  subclassCode?: number;
  protocolCode?: number;
  serialNumber?: string;
}

declare global {
  interface Navigator {
    usb: USBManager;
  }
}
// --- End WebUSB Type Definitions ---

/**
 * Service to handle WebUSB connections to Android devices.
 */
class AdbService {
  private device: USBDevice | null = null;
  private connected: boolean = false;

  // ADB Interface Constants
  private readonly ADB_INTERFACE_CLASS = 255;
  private readonly ADB_INTERFACE_SUBCLASS = 66;
  private readonly ADB_INTERFACE_PROTOCOL = 1;

  isSupported(): boolean {
    return !!(navigator.usb);
  }

  /**
   * Tries to find an already paired device and connect to it (without user prompt).
   * This is used for auto-reconnection on page load.
   */
  async restoreConnection(): Promise<DeviceInfo | null> {
    if (!this.isSupported()) return null;

    try {
      const devices = await navigator.usb.getDevices();
      if (devices.length === 0) return null;

      // Try to connect to the first available device that looks like ADB
      const device = devices[0]; // Simplified for demo

      await this.initializeDevice(device);
      return this.mapToDeviceInfo(device, 'connected');
    } catch (e) {
      console.log("Auto-connection failed (requires user gesture or device not ready):", e);
      return null;
    }
  }

  async getPairedDevices(): Promise<DeviceInfo[]> {
    if (!this.isSupported()) return [];

    try {
      const devices = await navigator.usb.getDevices();
      return devices.map(d => this.mapToDeviceInfo(d, 'connected'));
    } catch (e) {
      console.error("Failed to get paired devices:", e);
      return [];
    }
  }

  async connect(): Promise<DeviceInfo> {
    if (!this.isSupported()) {
      throw new Error("WebUSB is not supported in this browser. Please use Chrome or Edge.");
    }

    try {
      // 1. Request the physical device via Browser Picker
      let device: USBDevice;
      try {
        device = await navigator.usb.requestDevice({
          filters: [] 
        });
      } catch (reqErr: any) {
        if (reqErr.name === 'SecurityError' && reqErr.message?.includes('permissions policy')) {
           throw new Error("WebUSB access is blocked by the environment. Please ensure 'usb' permission is allowed in the browser/iframe settings.");
        }
        throw reqErr;
      }

      await this.initializeDevice(device);

      return this.mapToDeviceInfo(device, 'connected');

    } catch (e) {
      console.error("Connection failed:", e);
      throw e;
    }
  }

  private async initializeDevice(device: USBDevice) {
    // 2. Open Session
    await device.open();

    // 3. Select Configuration
    if (device.configuration === null) {
      await device.selectConfiguration(1);
    }

    // 4. Claim Interface
    const interfaceNumber = this.findAdbInterface(device);

    if (interfaceNumber !== -1) {
      try {
        await device.claimInterface(interfaceNumber);
        console.log("Interface claimed successfully");
      } catch (claimError) {
        console.warn("Could not claim ADB interface. Device might be in use by another program or tab.", claimError);
        // We continue anyway so the UI updates
      }
    } else {
        console.warn("No specific ADB interface found, using default.");
    }

    this.device = device;
    this.connected = true;
    console.log("USB Device Initialized:", device.productName);
  }

  async disconnect(): Promise<void> {
    if (this.device && this.device.opened) {
      try {
        await this.device.close();
      } catch (e) {
        console.warn("Error closing device:", e);
      }
    }
    this.device = null;
    this.connected = false;
  }

  private isAdbDevice(device: USBDevice): boolean {
    return true; 
  }

  private findAdbInterface(device: USBDevice): number {
    const iface = device.configuration?.interfaces.find(iface => 
      iface.alternates.some(alt => 
        alt.interfaceClass === this.ADB_INTERFACE_CLASS &&
        alt.interfaceSubclass === this.ADB_INTERFACE_SUBCLASS &&
        alt.interfaceProtocol === this.ADB_INTERFACE_PROTOCOL
      )
    );
    return iface ? iface.interfaceNumber : -1;
  }

  private mapToDeviceInfo(device: USBDevice, status: DeviceInfo['status']): DeviceInfo {
    return {
      id: device.serialNumber || 'unknown-serial',
      name: device.productName || 'Android Device',
      model: device.manufacturerName || 'Generic',
      status: status, 
      batteryLevel: 85 // Mock battery for UI
    };
  }

  // --- ADB Protocol Stubs ---

  async sendKeyEvent(keyCode: number): Promise<void> {
    if (!this.connected) return;
    console.log(`[RealUSB] Sending KeyCode ${keyCode}`);
  }

  async tap(x: number, y: number): Promise<void> {
    if (!this.connected) return;
    console.log(`[RealUSB] Sending Tap (${x},${y})`);
  }

  async swipe(x1: number, y1: number, x2: number, y2: number, duration: number): Promise<void> {
    if (!this.connected) return;
    console.log(`[RealUSB] Sending Swipe`);
  }

  async terminateApp(packageName: string): Promise<void> {
    if (!this.connected) return;
    console.log(`[RealUSB] Sending Force Stop ${packageName}`);
  }

  // --- Data Fetchers (Mocked for Demo UI) ---

  async getTopActivity(): Promise<AppStackInfo | null> {
    if (!this.connected) return null;
    // Return mock data so the UI looks active
    return {
      packageName: 'com.android.settings',
      activityName: 'com.android.settings.SettingsActivity',
      taskId: 1024,
      isRunning: true
    };
  }

  async getEnvironment(): Promise<AppEnvInfo | null> {
     if (!this.connected) return null;
     return {
       environment: 'DEVELOPMENT',
       versionCode: 33,
       versionName: '13.0',
       debuggable: true
     };
  }

  async getH5Info(): Promise<H5Info | null> {
    if (!this.connected) return null;
    return {
      currentUrl: null,
      pageTitle: null,
      userAgent: ""
    };
  }

  async getLayoutHierarchy(): Promise<LayoutNode | null> {
    if (!this.connected) return null;
     return {
      id: 'root',
      class: 'FrameLayout',
      bounds: '[0,0][1080,2400]',
      children: [
        { id: 'action_bar', class: 'Toolbar', bounds: '[0,0][1080,144]' },
        { id: 'content', class: 'LinearLayout', bounds: '[0,144][1080,2400]' }
      ]
    };
  }

  subscribeLogs(callback: (log: LogEntry) => void): () => void {
    if (!this.connected) return () => {};
    // Simulate some heartbeat logs
    const i = setInterval(() => {
        const tags = ['ActivityManager', 'PowerManager', 'UsbService'];
        callback({
            timestamp: new Date().toLocaleTimeString(),
            level: LogLevel.DEBUG,
            tag: tags[Math.floor(Math.random() * tags.length)],
            message: "Heartbeat: Device is connected and active"
        });
    }, 3000);
    return () => clearInterval(i);
  }

  async captureScreen(): Promise<string> {
    return ""; 
  }

  // Dev Tools
  async toggleLayoutBounds(): Promise<boolean> { return true; }
  async toggleShowTaps(): Promise<boolean> { return true; }
  async clearAppData(pkg: string): Promise<void> {}
  async restartApp(pkg: string): Promise<void> {}
}

