import React, { useState, useEffect, useCallback } from 'react';
import { Activity, Box, Layers, Globe, Terminal, Cpu, Usb, AlertCircle, RefreshCw, Smartphone, Wrench } from 'lucide-react';
import { adbService } from './services/adbService';
import { DeviceInfo, AppStackInfo, AppEnvInfo, H5Info, LogEntry, LayoutNode } from './types';
import { ScreenMirror } from './components/ScreenMirror';
import { InfoPanel } from './components/InfoPanel';
import { DevTools } from './components/DevTools';

const App: React.FC = () => {
  const [device, setDevice] = useState<DeviceInfo | null>(null);
  const [connecting, setConnecting] = useState(false);
  const [errorMsg, setErrorMsg] = useState<string | null>(null);
  const [activeTab, setActiveTab] = useState<'stack' | 'layout' | 'logs' | 'tools'>('stack');

  // Data States
  const [stackInfo, setStackInfo] = useState<AppStackInfo | null>(null);
  const [envInfo, setEnvInfo] = useState<AppEnvInfo | null>(null);
  const [h5Info, setH5Info] = useState<H5Info | null>(null);
  const [layout, setLayout] = useState<LayoutNode | null>(null);
  const [logs, setLogs] = useState<LogEntry[]>([]);
  const [loadingData, setLoadingData] = useState(false);

  const handleConnect = async () => {
    setConnecting(true);
    setErrorMsg(null);
    try {
      const dev = await adbService.connect();
      setDevice(dev);
      // Auto fetch data on connect
      fetchDeviceData();
    } catch (err: any) {
      console.error("Failed to connect", err);
      // Simplify error message for UI
      let msg = err.message;
      if (msg.includes('No ADB interface')) msg = 'USB Debugging not enabled on device.';
      if (msg.includes('No device selected')) msg = null; // User cancelled picker

      setErrorMsg(msg || "Connection failed.");
    } finally {
      setConnecting(false);
    }
  };

  // Attempt auto-connect on mount if permission already granted
  useEffect(() => {
    const autoConnect = async () => {
      // Try to restore connection if device is already plugged in and permission granted
      try {
        const restoredDevice = await adbService.restoreConnection();
        if (restoredDevice) {
            console.log("Auto-connected to:", restoredDevice.name);
            setDevice(restoredDevice);
            // We can't fetch data immediately in this render cycle inside async effect without care,
            // but the useEffect below observing `device` will trigger polling.
        }
      } catch (e) {
          console.log("Auto-connect failed, waiting for user interaction.");
      }
    };
    autoConnect();
  }, []);

  const handleDisconnect = async () => {
    await adbService.disconnect();
    setDevice(null);
    setStackInfo(null);
    setEnvInfo(null);
    setH5Info(null);
    setLogs([]);
  };

  const fetchDeviceData = useCallback(async () => {
    if (!device) return;
    setLoadingData(true);
    try {
        const [stack, env, h5, layoutData] = await Promise.all([
            adbService.getTopActivity(),
            adbService.getEnvironment(),
            adbService.getH5Info(),
            adbService.getLayoutHierarchy()
        ]);
        setStackInfo(stack);
        setEnvInfo(env);
        setH5Info(h5);
        setLayout(layoutData);
    } catch (e) {
        console.error("Error fetching data", e);
    } finally {
        setLoadingData(false);
    }
  }, [device]);

  useEffect(() => {
    if (device) {
      // Initial fetch
      fetchDeviceData();

      // Poll data every 5 seconds
      const poll = setInterval(fetchDeviceData, 5000);

      // Subscribe to logs
      const unsubscribe = adbService.subscribeLogs((log) => {
        setLogs(prev => [log, ...prev].slice(0, 100)); // Keep last 100 logs
      });

      return () => {
        clearInterval(poll);
        unsubscribe();
      };
    }
  }, [device, fetchDeviceData]);

  return (
    <div className="min-h-screen bg-slate-950 text-slate-200 flex flex-col font-sans">
      {/* Header */}
      <header className="h-16 bg-slate-900 border-b border-slate-800 flex items-center justify-between px-6 z-10 shrink-0">
        <div className="flex items-center gap-3">
          <div className="w-8 h-8 rounded-lg bg-cyan-500/10 flex items-center justify-center border border-cyan-500/20">
            <Cpu size={20} className="text-cyan-400" />
          </div>
          <h1 className="text-lg font-bold tracking-tight text-white">Droid<span className="text-cyan-400">Scope</span></h1>
        </div>

        <div className="flex items-center gap-4">
            {errorMsg && (
                <div className="text-xs text-red-400 bg-red-950/30 px-3 py-1 rounded border border-red-900/50 flex items-center gap-2">
                    <AlertCircle size={12} />
                    {errorMsg}
                </div>
            )}
          {device ? (
            <div className="flex items-center gap-4 bg-slate-800/50 px-4 py-1.5 rounded-full border border-slate-700">
              <div className="flex flex-col items-end leading-none">
                <span className="text-xs font-medium text-slate-200">{device.name}</span>
                <span className="text-[10px] text-green-400 uppercase tracking-wider">{device.status}</span>
              </div>
              <button 
                onClick={handleDisconnect}
                className="p-1 hover:bg-slate-700 rounded-full transition-colors text-slate-400 hover:text-red-400"
              >
                <AlertCircle size={16} />
              </button>
            </div>
          ) : (
            <button 
              onClick={handleConnect}
              disabled={connecting}
              className="flex items-center gap-2 bg-cyan-600 hover:bg-cyan-500 text-white px-4 py-2 rounded-lg text-sm font-medium transition-colors shadow-lg shadow-cyan-900/20 disabled:opacity-50"
            >
              {connecting ? <RefreshCw className="animate-spin" size={16} /> : <Usb size={16} />}
              {connecting ? 'Connecting...' : 'Connect USB Device'}
            </button>
          )}
        </div>
      </header>

      {/* Main Content */}
      <main className="flex-1 p-6 grid grid-cols-1 lg:grid-cols-12 gap-6 overflow-hidden">

        {/* Left Column: Screen Mirror */}
        <div className="lg:col-span-4 h-full flex flex-col min-h-[500px]">
           <ScreenMirror connected={!!device} />
        </div>

        {/* Right Column: Information Grid */}
        <div className="lg:col-span-8 h-full flex flex-col gap-6 overflow-hidden">

          {/* Top Row: Info Panels */}
          <div className="grid grid-cols-1 md:grid-cols-3 gap-6 shrink-0 h-64">

            <InfoPanel title="Top Activity" icon={Layers} loading={loadingData}>
              {stackInfo ? (
                <div className="space-y-4">
                  <div>
                    <span className="text-[10px] uppercase text-slate-500 font-bold tracking-wider">Activity</span>
                    <p className="text-sm font-mono text-cyan-300 break-all">{stackInfo.activityName.split('.').pop()}</p>
                  </div>
                  <div>
                    <span className="text-[10px] uppercase text-slate-500 font-bold tracking-wider">Package</span>
                    <p className="text-xs text-slate-400 break-all">{stackInfo.packageName}</p>
                  </div>
                  <div className="flex gap-2">
                     <span className={`text-[10px] px-2 py-0.5 rounded border ${stackInfo.isRunning ? 'border-green-800 bg-green-900/30 text-green-400' : 'border-red-800 bg-red-900/30 text-red-400'}`}>
