// Declare the global WebADB object injected by the script tag
declare global {
  interface Window {
    WebADB: any;
  }
}

class AdbService {
  private adb: any = null;
  private connected: boolean = false;
  private isRecording: boolean = false;
  private shellParser: any = null; // Helper to parse shell output if needed

  isSupported(): boolean {
    return !!navigator.usb && !!window.WebADB;
  }

  async restoreConnection(): Promise<DeviceInfo | null> {
    // WebADB doesn't easily support silent restore without user gesture security policies usually
    // But we can check if we have a device instance
    return null;
  }

  async connect(): Promise<DeviceInfo> {
    if (!this.isSupported()) {
      throw new Error("环境不支持: 请使用 Chrome/Edge 并确保加载了 WebADB 库");
    }

    try {
      // Create WebADB instance
      this.adb = new window.WebADB();

      // Open browser picker
      await this.adb.connect();

      this.connected = true;

      // Basic Info
      const deviceName = this.adb.device?.productName || "Android Device";
      const manufacturer = this.adb.device?.manufacturerName || "Google";
      const serial = this.adb.device?.serialNumber || "usb-device";

      return {
        id: serial,
        name: deviceName,
        model: manufacturer,
        status: 'connected',
        batteryLevel: await this.getBatteryLevel()
      };
    } catch (e: any) {
      console.error("ADB Connect Error:", e);
      this.connected = false;
      this.adb = null;
      throw new Error(e.message || "连接失败，请确保手机已开启 USB 调试");
    }
  }

  async disconnect(): Promise<void> {
    if (this.adb) {
      // WebADB usually disconnects when the device is released
      this.adb = null;
    }
    this.connected = false;
  }

  // --- Real ADB Commands ---

  async sendKeyEvent(keyCode: number): Promise<void> {
    if (!this.connected || !this.adb) return;
    await this.adb.shell(`input keyevent ${keyCode}`);
  }

  async tap(x: number, y: number): Promise<void> {
    if (!this.connected || !this.adb) return;
    await this.adb.shell(`input tap ${x} ${y}`);
  }

  async swipe(x1: number, y1: number, x2: number, y2: number, duration: number): Promise<void> {
    if (!this.connected || !this.adb) return;
    await this.adb.shell(`input swipe ${x1} ${y1} ${x2} ${y2} ${duration}`);
  }

  async terminateApp(packageName: string): Promise<void> {
    if (!this.connected || !this.adb) return;
    await this.adb.shell(`am force-stop ${packageName}`);
  }

  // --- Data Fetchers (Real Shell Commands) ---

  async getBatteryLevel(): Promise<number> {
      try {
          const output = await this.execShell('dumpsys battery | grep level');
          // Output format: "  level: 85"
          const match = output.match(/level:\s*(\d+)/);
          return match ? parseInt(match[1], 10) : 50;
      } catch (e) {
          return 50;
      }
  }

  async getTopActivity(): Promise<AppStackInfo | null> {
    if (!this.connected || !this.adb) return null;
    try {
        const output = await this.execShell('dumpsys activity activities | grep mResumedActivity');
        // Example: mResumedActivity: ActivityRecord{... u0 com.android.settings/.SettingsActivity t123}
        const match = output.match(/u0\s+([^\s\/]+)\/([^\s]+)\s+t(\d+)/);

        if (match) {
            return {
                packageName: match[1],
                activityName: match[2].startsWith('.') ? match[1] + match[2] : match[2],
                taskId: parseInt(match[3]),
                isRunning: true
            };
        }
        return {
             packageName: 'System',
             activityName: 'Unknown',
             taskId: 0,
             isRunning: true
        };
    } catch (e) {
        console.warn("Get top activity failed", e);
        return null;
    }
  }

  async getEnvironment(): Promise<AppEnvInfo | null> {
     if (!this.connected || !this.adb) return null;
     try {
         const ver = await this.execShell('getprop ro.build.version.release');
         const sdk = await this.execShell('getprop ro.build.version.sdk');
         return {
            environment: 'DEVELOPMENT',
            versionCode: parseInt(sdk.trim()),
            versionName: `Android ${ver.trim()}`,
            debuggable: true
         };
     } catch (e) {
         return null;
     }
  }

  async getH5Info(): Promise<H5Info | null> {
    // Real Webview debugging via ADB requires forwarding a socket to local abstract port
    // and querying thedevtools frontend. This is too complex for this demo.
    // Returning placeholder to indicate support exists in full versions.
    if (!this.connected) return null;
    return {
      currentUrl: null,
      pageTitle: null,
      userAgent: ""
    };
  }

  async getLayoutHierarchy(): Promise<LayoutNode | null> {
    // Getting real layout XML via `uiautomator dump` is very slow (5s+).
    // Skipping for performance in this real-time tool.
    return null;
  }

  subscribeLogs(callback: (log: LogEntry) => void): () => void {
    if (!this.connected || !this.adb) return () => {};

    // In a full implementation, we would stream `logcat -v threadtime`.
    // WebADB's shell command returns a textual accumulator, streaming logs requires a custom reader.
    // For stability in this demo, we will use a simulated heartbeat or one-time fetch.

    // Let's do a one-time fetch of recent logs
    this.execShell('logcat -d -t 5 -v threadtime').then(output => {
        const lines = output.split('\n');
        lines.forEach(line => {
             if(line.length < 10) return;
             // Very basic parse
             callback({
                 timestamp: line.substring(0, 18),
                 level: LogLevel.INFO,
                 tag: 'ADB',
                 message: line.substring(20) // simplify
             });
        });
    });

    return () => {};
  }

  // --- Real Screenshot via ADB ---

  async captureScreen(): Promise<string> {
    if (!this.connected || !this.adb) throw new Error("Device disconnected");

    // We use `screencap -p` to get a PNG.
    // NOTE: This transfers ~3-5MB of data per frame over USB JS bridge. It might take 500ms-2s.
    try {
        const blob = await this.adb.screencap();
        if (!blob) throw new Error("Empty screenshot");

        return URL.createObjectURL(blob);
    } catch (e) {
        console.error("Capture failed:", e);
        // Fallback to a simulation if real capture fails heavily so app doesn't look broken
        throw e;
    }
  }

  async toggleScreenRecording(): Promise<boolean> {
      // Real recording requires `screenrecord` command and pulling the file later.
      // Not suitable for "toggle" streaming in this simple arch.
      this.isRecording = !this.isRecording;
      return this.isRecording;
  }

  // --- Helper ---

  private async execShell(command: string): Promise<string> {
      if (!this.adb) return "";
      return await this.adb.shell(command);
  }

  // Dev Tools
  async toggleLayoutBounds(): Promise<boolean> { 
      const current = await this.execShell('getprop debug.layout');
      const next = current.trim() === 'true' ? 'false' : 'true';
      await this.execShell(`setprop debug.layout ${next} && service call activity 1599295570`); // Force layout update
      return next === 'true';
  }

  async toggleShowTaps(): Promise<boolean> { 
       const current = await this.execShell('settings get system show_touches');
       const next = current.trim() === '1' ? '0' : '1';
       await this.execShell(`settings put system show_touches ${next}`);
       return next === '1';
  }

  async clearAppData(pkg: string): Promise<void> {
      await this.execShell(`pm clear ${pkg}`);
  }

  async restartApp(pkg: string): Promise<void> {
      await this.terminateApp(pkg);
      await this.execShell(`monkey -p ${pkg} -c android.intent.category.LAUNCHER 1`);
  }
}

