import { DeviceInfo, AppStackInfo, AppEnvInfo, H5Info, LayoutNode, LogEntry, LogLevel } from '../types';

// Declare the global WebADB object injected by the script tag
declare global {
  interface Window {
    WebADB: any;
  }
  interface Navigator {
    usb: any;
  }
}

class AdbService {
  private adb: any = null;
  private connected: boolean = false;
  private isRecording: boolean = false;

  isSupported(): boolean {
    // We check specific features inside connect() for better error messages
    return true; 
  }

  async restoreConnection(): Promise<DeviceInfo | null> {
    if (!navigator.usb) return null;
    try {
        const devices = await navigator.usb.getDevices();
        if (devices.length > 0) {
            console.log("Found paired devices:", devices);
            // WebADB currently requires a fresh instance and user trigger for the most part,
            // but we can signal that devices are available.
            // For this demo, we won't auto-reconnect deeply to avoid complex state,
            // but simply return null to prompt user to click "Connect".
            return null;
        }
    } catch (e) {
        console.warn("Auto-connect check failed", e);
    }
    return null;
  }

  async connect(): Promise<DeviceInfo> {
    // 1. Check for WebUSB support (Requires HTTPS or Localhost)
    if (!navigator.usb) {
      throw new Error("WebUSB 不可用。请使用 Chrome/Edge 浏览器，并确保当前页面通过 HTTPS 或 localhost 访问。");
    }

    // 2. Check if WebADB library loaded
    if (!window.WebADB) {
      throw new Error("WebADB 组件加载失败。可能是网络问题导致 CDN 脚本未加载，请尝试刷新页面。");
    }

    try {
      // Create WebADB instance
      this.adb = new window.WebADB();

      // Open browser picker
      // This MUST be triggered by a user gesture (button click)
      await this.adb.connect();

      this.connected = true;

      // Basic Info
      const deviceName = this.adb.device?.productName || "Android Device";
      const manufacturer = this.adb.device?.manufacturerName || "Google";
      const serial = this.adb.device?.serialNumber || "usb-device";

      return {
        id: serial,
        name: deviceName,
        model: manufacturer,
        status: 'connected',
        batteryLevel: await this.getBatteryLevel()
      };
    } catch (e: any) {
      console.error("ADB Connect Error:", e);
      this.connected = false;
      this.adb = null;

      if (e.name === 'NotFoundError' || e.message?.includes('No device selected')) {
          throw new Error("用户取消了设备选择");
      }
      if (e.name === 'SecurityError') {
          throw new Error("访问被拒绝：请检查浏览器权限设置");
      }

      throw new Error(e.message || "连接失败，请确保手机已开启 USB 调试并授权电脑连接");
    }
  }

  async disconnect(): Promise<void> {
    if (this.adb) {
      try {
        await this.adb.disconnect();
      } catch (e) { /* ignore */ }
      this.adb = null;
    }
    this.connected = false;
  }

  // --- Real ADB Commands ---

  async sendKeyEvent(keyCode: number): Promise<void> {
    if (!this.connected || !this.adb) return;
    try {
        await this.adb.shell(`input keyevent ${keyCode}`);
    } catch (e) { console.warn("Key event failed", e); }
  }

  async tap(x: number, y: number): Promise<void> {
    if (!this.connected || !this.adb) return;
    await this.adb.shell(`input tap ${x} ${y}`);
  }

  async swipe(x1: number, y1: number, x2: number, y2: number, duration: number): Promise<void> {
    if (!this.connected || !this.adb) return;
    await this.adb.shell(`input swipe ${x1} ${y1} ${x2} ${y2} ${duration}`);
  }

  async terminateApp(packageName: string): Promise<void> {
    if (!this.connected || !this.adb) return;
    await this.adb.shell(`am force-stop ${packageName}`);
  }

  // --- Data Fetchers (Real Shell Commands) ---

  async getBatteryLevel(): Promise<number> {
      try {
          const output = await this.execShell('dumpsys battery | grep level');
          // Output format: "  level: 85"
          const match = output.match(/level:\s*(\d+)/);
          return match ? parseInt(match[1], 10) : 50;
      } catch (e) {
          return 50;
      }
  }

  async getTopActivity(): Promise<AppStackInfo | null> {
    if (!this.connected || !this.adb) return null;
    try {
        // This command works on most modern Android versions
        const output = await this.execShell('dumpsys activity activities | grep -E "mResumedActivity|mFocusedActivity"');
        // Example match: mResumedActivity: ActivityRecord{... u0 com.package/com.package.Activity t123}
        const match = output.match(/u0\s+([^\s\/]+)\/([^\s]+)\s+t(\d+)/);

        if (match) {
            let pkg = match[1];
            let activity = match[2];
            if (activity.startsWith('.')) activity = pkg + activity;

            return {
                packageName: pkg,
                activityName: activity,
                taskId: parseInt(match[3]),
                isRunning: true
            };
        }
        return {
             packageName: 'System',
             activityName: 'Launcher/Unknown',
             taskId: 0,
             isRunning: true
        };
    } catch (e) {
        console.warn("Get top activity failed", e);
        return null;
    }
  }

  async getEnvironment(): Promise<AppEnvInfo | null> {
     if (!this.connected || !this.adb) return null;
     try {
         const ver = await this.execShell('getprop ro.build.version.release');
         const sdk = await this.execShell('getprop ro.build.version.sdk');
         return {
            environment: 'DEVELOPMENT', // Hard to determine env from adb alone without app context
            versionCode: parseInt(sdk.trim()),
            versionName: `Android ${ver.trim()}`,
            debuggable: true
         };
     } catch (e) {
         return null;
     }
  }

  async getH5Info(): Promise<H5Info | null> {
    if (!this.connected) return null;
    return {
      currentUrl: null, // Requires DevTools Protocol which is complex over raw ADB shell
      pageTitle: null,
      userAgent: ""
    };
  }

  async getLayoutHierarchy(): Promise<LayoutNode | null> {
    return null; // Too slow for realtime
  }

  subscribeLogs(callback: (log: LogEntry) => void): () => void {
    if (!this.connected || !this.adb) return () => {};

    // Polling logs occasionally to avoid blocking the single command channel too much
    // Real implementation would use a separate stream
    const i = setInterval(() => {
        this.execShell('logcat -d -t 10 -v threadtime *:I').then(output => {
            if (!output) return;
            const lines = output.split('\n');
            lines.forEach(line => {
                if(line.length < 20) return;
                // Basic parse: 12-29 14:03:20.123  PID  TID L TAG: Message
                const parts = line.split(/\s+/);
                if (parts.length > 5) {
                    const levelChar = parts[4];
                    let level = LogLevel.INFO;
                    if (levelChar === 'E') level = LogLevel.ERROR;
                    if (levelChar === 'W') level = LogLevel.WARN;
                    if (levelChar === 'D') level = LogLevel.DEBUG;

                    callback({
                        timestamp: parts[1] || '',
                        level: level,
                        tag: parts[5]?.replace(':', '') || 'System',
                        message: parts.slice(6).join(' ')
                    });
                }
            });
        }).catch(() => {});
    }, 2000);

    return () => clearInterval(i);
  }

  // --- Real Screenshot via ADB ---

  async captureScreen(): Promise<string> {
    if (!this.connected || !this.adb) throw new Error("Device disconnected");

    try {
        // Uses webadb's internal screencap helper if available, or implements manual frame reading
        // webadb.js on master has a .screencap() method
        const blob = await this.adb.screencap();
        if (!blob) throw new Error("Empty screenshot");
        return URL.createObjectURL(blob);
    } catch (e) {
        console.error("Capture failed:", e);
        throw e;
    }
  }

  async toggleScreenRecording(): Promise<boolean> {
      this.isRecording = !this.isRecording;
      return this.isRecording;
  }

  // --- Helper ---

  private async execShell(command: string): Promise<string> {
      if (!this.adb) return "";
      try {
          return await this.adb.shell(command);
      } catch (e) {
          console.warn(`CMD Failed: ${command}`, e);
          return "";
      }
  }

  // Dev Tools
  async toggleLayoutBounds(): Promise<boolean> { 
      const current = await this.execShell('getprop debug.layout');
      const next = current.trim() === 'true' ? 'false' : 'true';
      await this.execShell(`setprop debug.layout ${next}`);
      await this.execShell('service call activity 1599295570'); // Force layout refresh
      return next === 'true';
  }

  async toggleShowTaps(): Promise<boolean> { 
       const current = await this.execShell('settings get system show_touches');
       const next = current.trim() === '1' ? '0' : '1';
       await this.execShell(`settings put system show_touches ${next}`);
       return next === '1';
  }

  async clearAppData(pkg: string): Promise<void> {
      await this.execShell(`pm clear ${pkg}`);
  }

  async restartApp(pkg: string): Promise<void> {
      await this.terminateApp(pkg);
      await this.execShell(`monkey -p ${pkg} -c android.intent.category.LAUNCHER 1`);
  }
}

