}

// The classic WebADB library URL
const WEBADB_LIB_URL = "https://cdn.jsdelivr.net/gh/webadb/webadb.js@master/webadb.js";

class AdbService {
  private adb: any = null;
  private connected: boolean = false;
  private isRecording: boolean = false;
