  isSupported(): boolean {
    return !!navigator.usb; 
  }

  // Dynamically load the script when needed
  private async ensureLibraryLoaded(): Promise<void> {
    if (window.Adb) return;

    if (!this.scriptPromise) {
        this.scriptPromise = new Promise((resolve, reject) => {
            const script = document.createElement('script');
            script.src = WEBADB_LIB_URL;
            script.async = true;
            script.onload = () => {
                if (window.Adb) {
                    resolve();
                } else {
                    reject(new Error("WebADB 脚本加载完成，但 'Adb' 对象未找到。可能脚本版本不兼容。"));
                }
            };
            script.onerror = () => {
                this.scriptPromise = null; // Reset on failure so we can try again
                reject(new Error("WebADB 脚本下载失败。请检查网络连接 (需要访问 jsdelivr CDN)。"));
            };
            document.body.appendChild(script);
        });
    }
    return this.scriptPromise;
  }

  async restoreConnection(): Promise<DeviceInfo | null> {
    if (!navigator.usb) return null;
    // We don't want to trigger script load on pure restore check unless we know we have devices
    // But since we can't check devices without permission, we just skip auto-init logic heavily
    return null;
