      console.error("ADB Connect Error:", e);
      this.connected = false;
      this.adb = null;

      if (e.name === 'NotFoundError' || e.message?.includes('No device selected')) {
          throw new Error("用户取消了设备选择");
      }
      if (e.name === 'SecurityError') {
          throw new Error("访问被拒绝：请确保没有其他页面正在占用该设备，并重试");
      }

      throw new Error(e.message || "连接建立失败，请确保手机已开启 USB 调试");
    }
