    const i = setInterval(() => {
        // -d: dump and exit, -t 50: last 50 lines, -v threadtime: specific format
        this.execShell('logcat -d -t 50 -v threadtime *:I').then(output => {
            if (!output) return;
            const lines = output.split('\n');
            lines.forEach(line => {
                if(line.length < 20) return;
