  private connected: boolean = false;
  private isRecording: boolean = false;

  isSupported(): boolean {
    return !!navigator.usb; 
  }

  // Poll for the global Adb object to be ready
  private async waitForSDK(): Promise<void> {
    if (window.Adb) return;

    // Check every 100ms for up to 3 seconds
    for (let i = 0; i < 30; i++) {
        if (window.Adb) return;
        await new Promise(resolve => setTimeout(resolve, 100));
    }
    throw new Error("WebADB SDK 加载失败，请检查网络连接 (jsdelivr CDN)");
  }

  // Simulate 'adb devices' logic using WebUSB API
  async getPairedDevices(): Promise<any[]> {
    if (!navigator.usb) return [];
    try {
        const devices = await navigator.usb.getDevices();
        return devices;
    } catch (e) {
        console.warn("Could not get devices", e);
        return [];
    }
  }

  async connect(): Promise<DeviceInfo> {
    // 1. Check for WebUSB support
    if (!navigator.usb) {
      throw new Error("浏览器不支持 WebUSB。请使用 Chrome/Edge，并确保通过 HTTPS 或 localhost 访问。");
    }

    // 2. Wait for library
    await this.waitForSDK();

    try {
      // 3. Initialize Transport Layer (Correct Usage: Adb.open, NOT new Adb)
      // The library exposes 'Adb' object with 'open' method.
      if (typeof window.Adb.open !== 'function') {
          throw new Error("WebADB 库版本不兼容 (缺少 open 方法)");
      }

      this.webusb = await window.Adb.open("WebUSB");

      // 4. Connect logic
      // First, check if we have paired devices to avoid unnecessary popup if possible, 
      // though connect() usually forces a user gesture if not claimed.
      // But Adb.js 'connect()' wraps navigator.usb.requestDevice

      // Note: Adb.js's webusb.connect() will trigger the browser picker.
      await this.webusb.connect();

      // 5. Handshake (Adb Connect)
      this.adb = await this.webusb.connectAdb("host::");

      this.connected = true;

      // Use the raw USB device object from the transport layer for metadata
      const rawDevice = this.webusb.device; 

      const deviceName = rawDevice?.productName || "Android Device";
      const manufacturer = rawDevice?.manufacturerName || "Google";
      const serial = rawDevice?.serialNumber || "usb-device";

      return {
        id: serial,
        name: deviceName,
        model: manufacturer,
        status: 'connected',
        batteryLevel: await this.getBatteryLevel()
      };
    } catch (e: any) {
      console.error("ADB Connect Logic Error:", e);
      this.cleanup();

      // Detailed Error Handling
      if (e.name === 'NotFoundError' || e.message?.includes('No device selected')) {
          // Check if it's because no devices were shown in the list vs user clicked cancel
          // We can't strictly distinguish, but we can give a hint.
          throw new Error("用户取消了选择，或未在列表中看到设备。\n提示：如果列表为空，请检查 USB 线或 Windows 驱动 (Zadig)。");
