import { DeviceInfo, AppStackInfo, AppEnvInfo, H5Info, LayoutNode, LogEntry, LogLevel } from '../types';

declare global {
  interface Window {
    Adb: any;
  }
  interface Navigator {
    usb: any;
  }
}

class AdbService {
  private adb: any = null; // The Adb Client instance
  private webusb: any = null; // The WebUSB transport layer
  private connected: boolean = false;
  private isRecording: boolean = false;

  isSupported(): boolean {
    return !!navigator.usb; 
  }

  // Poll for the global Adb object to be ready
  private async waitForSDK(): Promise<void> {
    if (window.Adb) return;

    // Check every 100ms for up to 3 seconds
    for (let i = 0; i < 30; i++) {
        if (window.Adb) return;
        await new Promise(resolve => setTimeout(resolve, 100));
    }
    throw new Error("WebADB SDK 加载失败，请检查网络连接 (jsdelivr CDN)");
  }

  // Simulate 'adb devices' logic using WebUSB API
  // This lists devices that the user has previously granted permission to access via WebUSB.
  async getPairedDevices(): Promise<any[]> {
    if (!navigator.usb) return [];
    try {
        const devices = await navigator.usb.getDevices();
        return devices;
    } catch (e) {
        console.warn("Could not get devices", e);
        return [];
    }
  }

  async connect(): Promise<DeviceInfo> {
    // 1. Check for WebUSB support
    if (!navigator.usb) {
      throw new Error("浏览器不支持 WebUSB。请使用 Chrome/Edge，并确保通过 HTTPS 或 localhost 访问。");
    }

    // 2. Wait for library
    await this.waitForSDK();

    try {
      // 3. Initialize Transport Layer
      if (typeof window.Adb.open !== 'function') {
          throw new Error("WebADB 库版本不兼容 (缺少 open 方法)");
      }

      // 4. Open Connection
      // This will trigger the browser device picker.
      this.webusb = await window.Adb.open("WebUSB");

      // Delay: Give the hardware interface a moment to settle before sending ADB protocol packets.
      await new Promise(resolve => setTimeout(resolve, 500));

      // 5. Handshake (Adb Connect)
      try {
          // host:: tells ADB to connect as a host
          this.adb = await this.webusb.connectAdb("host::");
      } catch (handshakeErr: any) {
          console.error("Handshake failed:", handshakeErr);
          // Throw specific error for handshake to be caught below
          throw new Error(`HANDSHAKE_FAILED:${handshakeErr.message}`);
      }

      this.connected = true;

      // Use the raw USB device object from the transport layer for metadata
      const rawDevice = this.webusb.device; 

      const deviceName = rawDevice?.productName || "Android Device";
      const manufacturer = rawDevice?.manufacturerName || "Google";
      const serial = rawDevice?.serialNumber || "usb-device";

      return {
        id: serial,
        name: deviceName,
        model: manufacturer,
        status: 'connected',
        batteryLevel: await this.getBatteryLevel()
      };
    } catch (e: any) {
      console.error("ADB Connect Logic Error:", e);
      this.cleanup();

      // --- Smart Diagnostics ---

      // 1. Check if user cancelled or no device selected
      if (e.name === 'NotFoundError' || e.message?.includes('No device selected')) {
          // Check if we have paired devices (simulating 'adb devices')
          const paired = await this.getPairedDevices();
          if (paired.length === 0) {
               throw new Error("未检测到设备。\n请检查：\n1. USB 线是否连接良好\n2. Windows 用户是否安装了 Zadig 驱动");
          } else {
               // Devices exist but user cancelled or selected wrong one
               throw new Error("操作已取消。");
          }
      }

      // 2. Check for Permission Denied (Driver/Occupied)
      if (e.name === 'SecurityError' || e.message?.includes('Access denied')) {
          throw new Error("访问被拒绝 (SecurityError)。\n原因 1: Windows 需要安装 WinUSB 驱动 (使用 Zadig 工具)。\n原因 2: 另一程序 (如 Android Studio) 独占了设备，请关闭它们。");
      }

      if (e.message?.includes('ClaimInterface')) {
          throw new Error("接口被占用。\n请在终端运行 'adb kill-server' 停止本地 ADB 服务，然后重试。");
      }

      // 3. Check for Handshake Failure (Protocol Level)
      if (e.message?.includes('HANDSHAKE_FAILED') || e.message?.includes('closed') || e.message?.includes('auth')) {
          const paired = await this.getPairedDevices();
          const deviceName = paired.length > 0 ? (paired[0].productName || '设备') : '设备';

          throw new Error(
            `已连接到物理设备 "${deviceName}"，但 ADB 握手失败。\n\n` + 
            `关键解决步骤：\n` +
            `1. 在手机上打开【开发者选项】\n` +
            `2. 点击【撤销 USB 调试授权】(Revoke USB debugging authorizations)\n` +
            `3. 重新插拔 USB 线，并在弹窗时再次点击“允许”\n` + 
            `4. 重试连接`
          );
      }

      throw new Error(e.message || "连接建立失败");
    }
  }

  private cleanup() {
      this.connected = false;
      this.adb = null;
      this.webusb = null;
  }

  async disconnect(): Promise<void> {
    if (this.adb) {
      try {
        await this.adb.close(); // Close ADB session
      } catch (e) { /* ignore */ }
    }
    if (this.webusb) {
        try {
            // WebADB doesn't always expose close on transport, but we can try
            if (this.webusb.device && this.webusb.device.close) {
                await this.webusb.device.close();
            }
        } catch (e) { /* ignore */ }
    }
    this.cleanup();
  }

  // --- Real ADB Commands ---

  async sendKeyEvent(keyCode: number): Promise<void> {
    if (!this.connected || !this.adb) return;
    try {
        await this.adb.shell(`input keyevent ${keyCode}`);
    } catch (e) { console.warn("Key event failed", e); }
  }

  async tap(x: number, y: number): Promise<void> {
    if (!this.connected || !this.adb) return;
    await this.adb.shell(`input tap ${x} ${y}`);
  }

  async swipe(x1: number, y1: number, x2: number, y2: number, duration: number): Promise<void> {
    if (!this.connected || !this.adb) return;
    await this.adb.shell(`input swipe ${x1} ${y1} ${x2} ${y2} ${duration}`);
  }

  async terminateApp(packageName: string): Promise<void> {
    if (!this.connected || !this.adb) return;
    await this.adb.shell(`am force-stop ${packageName}`);
  }

  // --- Data Fetchers ---

  async getBatteryLevel(): Promise<number> {
      try {
          const output = await this.execShell('dumpsys battery | grep level');
          const match = output.match(/level:\s*(\d+)/);
          return match ? parseInt(match[1], 10) : 50;
      } catch (e) {
          return 50;
      }
  }

  async getTopActivity(): Promise<AppStackInfo | null> {
    if (!this.connected || !this.adb) return null;
    try {
        const output = await this.execShell('dumpsys activity activities | grep -E "mResumedActivity|mFocusedActivity" | tail -n 1');
        const match = output.match(/u0\s+([^\s\/]+)\/([^\s\}]+)/);

        if (match) {
            let pkg = match[1];
            let activity = match[2];
            if (activity.startsWith('.')) activity = pkg + activity;

            return {
                packageName: pkg,
                activityName: activity,
                taskId: 0,
                isRunning: true
            };
        }
        return {
             packageName: 'System',
             activityName: 'Launcher/Unknown',
             taskId: 0,
             isRunning: true
        };
    } catch (e) {
        return null;
    }
  }

  async getEnvironment(): Promise<AppEnvInfo | null> {
     if (!this.connected || !this.adb) return null;
     try {
         const ver = await this.execShell('getprop ro.build.version.release');
         const sdk = await this.execShell('getprop ro.build.version.sdk');
         return {
            environment: 'DEVELOPMENT',
            versionCode: parseInt(sdk.trim()),
            versionName: `Android ${ver.trim()}`,
            debuggable: true
         };
     } catch (e) {
         return null;
     }
  }

  async getH5Info(): Promise<H5Info | null> {
    if (!this.connected) return null;
    return {
      currentUrl: null,
      pageTitle: null,
      userAgent: ""
    };
  }

  async getLayoutHierarchy(): Promise<LayoutNode | null> {
    return null;
  }

  subscribeLogs(callback: (log: LogEntry) => void): () => void {
    if (!this.connected || !this.adb) return () => {};

    const i = setInterval(() => {
        this.execShell('logcat -d -t 50 -v threadtime *:I').then(output => {
            if (!output) return;
            const lines = output.split('\n');
            lines.forEach(line => {
                if(line.length < 20) return;
                const parts = line.split(/\s+/);
                if (parts.length > 5) {
                    const levelChar = parts[4]; 

                    if (['V','D','I','W','E','A','F'].includes(levelChar)) {
                        let level = LogLevel.INFO;
                        if (levelChar === 'E' || levelChar === 'F') level = LogLevel.ERROR;
                        if (levelChar === 'W') level = LogLevel.WARN;
                        if (levelChar === 'D') level = LogLevel.DEBUG;

                        const tagIndex = 5;
                        const messageIndex = 6;

                        callback({
                            timestamp: parts[1] || '',
                            level: level,
                            tag: parts[tagIndex]?.replace(':', '') || 'System',
                            message: parts.slice(messageIndex).join(' ')
                        });
                    }
                }
            });
        }).catch(() => {});
    }, 2000);

    return () => clearInterval(i);
  }

  async captureScreen(): Promise<string> {
    if (!this.connected || !this.adb) throw new Error("Device disconnected");

    try {
        const frame = await this.adb.framebuffer(); // WebADB uses 'framebuffer()' not screencap typically
        // frame is likely a Canvas or similar in WebADB js implementation, or raw bytes?
        // Let's check the library. Standard webadb.js returns a 'FrameBuffer' object which has toCanvas().

        if (frame && frame.toCanvas) {
            const canvas = frame.toCanvas();
            return canvas.toDataURL('image/png');
        } 

        // Fallback if the library version has screencap helper
        if (this.adb.screencap) {
             const blob = await this.adb.screencap();
             return URL.createObjectURL(blob);
        }

        throw new Error("Screenshot not supported by this ADB version");

    } catch (e) {
        console.error("Capture failed:", e);
        // Fallback to shell screencap (slow but reliable)
        try {
            // This is complex in browser without binary handling helper, skipping deep implementation
            throw e;
        } catch (e2) {
             throw e;
        }
    }
  }

  async toggleScreenRecording(): Promise<boolean> {
      this.isRecording = !this.isRecording;
      return this.isRecording;
  }

  private async execShell(command: string): Promise<string> {
      if (!this.adb) return "";
      try {
          // adb.shell returns a stream in webadb.js usually.
          // We need to read all output.
          // Or, some versions have shell(cmd) that returns string?
          // The standard one returns a stream. Let's handle it.

          const stream = await this.adb.shell(command);
          // Simple reader
          let output = '';
          const reader = stream.getReader ? stream.getReader() : null; // WebADB streams might be different

          // Actually, webadb.js shell() usually returns a custom Stream object, not WhatWG stream
          // It has on('data', ...)

          return new Promise((resolve) => {
              let buf = '';
              stream.on('data', (data: Uint8Array) => {
                   // Convert Uint8Array to string
                   const str = new TextDecoder("utf-8").decode(data);
                   buf += str;
              });
              stream.on('end', () => resolve(buf));
              stream.on('close', () => resolve(buf)); // fallback
          });

      } catch (e) {
          console.warn(`CMD Failed: ${command}`, e);
          return "";
      }
  }

  async toggleLayoutBounds(): Promise<boolean> { 
      const current = await this.execShell('getprop debug.layout');
      const next = current.trim() === 'true' ? 'false' : 'true';
      await this.execShell(`setprop debug.layout ${next}`);
      await this.execShell('service call activity 1599295570');
      return next === 'true';
  }

  async toggleShowTaps(): Promise<boolean> { 
       const current = await this.execShell('settings get system show_touches');
       const next = current.trim() === '1' ? '0' : '1';
       await this.execShell(`settings put system show_touches ${next}`);
       return next === '1';
  }

  async clearAppData(pkg: string): Promise<void> {
      await this.execShell(`pm clear ${pkg}`);
  }

  async restartApp(pkg: string): Promise<void> {
      await this.terminateApp(pkg);
      await this.execShell(`monkey -p ${pkg} -c android.intent.category.LAUNCHER 1`);
  }
}

export const adbService = new AdbService();

import React, { useState, useEffect, useCallback } from 'react';
import { Activity, Box, Layers, Globe, Terminal, Cpu, Usb, AlertCircle, RefreshCw, Smartphone, Wrench, HelpCircle } from 'lucide-react';
import { adbService } from './services/adbService';
import { DeviceInfo, AppStackInfo, AppEnvInfo, H5Info, LogEntry, LayoutNode } from './types';
import { ScreenMirror } from './components/ScreenMirror';
import { InfoPanel } from './components/InfoPanel';
import { DevTools } from './components/DevTools';

const App: React.FC = () => {
  const [device, setDevice] = useState<DeviceInfo | null>(null);
  const [connecting, setConnecting] = useState(false);
  const [errorMsg, setErrorMsg] = useState<string | null>(null);
  const [activeTab, setActiveTab] = useState<'stack' | 'layout' | 'logs' | 'tools'>('stack');

  // Data States
  const [stackInfo, setStackInfo] = useState<AppStackInfo | null>(null);
  const [envInfo, setEnvInfo] = useState<AppEnvInfo | null>(null);
  const [h5Info, setH5Info] = useState<H5Info | null>(null);
  const [layout, setLayout] = useState<LayoutNode | null>(null);
  const [logs, setLogs] = useState<LogEntry[]>([]);
  const [loadingData, setLoadingData] = useState(false);

  // Helper to determine if a real app is open
  const isAppOpen = stackInfo && 
                    stackInfo.packageName !== 'com.android.launcher' && 
                    stackInfo.packageName !== 'com.android.systemui';

  const handleConnect = async () => {
    setConnecting(true);
    setErrorMsg(null);
    try {
      const dev = await adbService.connect();
      setDevice(dev);
      // Auto fetch data on connect
      fetchDeviceData();
    } catch (err: any) {
      console.error("Failed to connect", err);
      // Simplify error message for UI
      let msg = err.message;
      if (msg.includes('No ADB interface')) msg = '设备未开启 USB 调试模式';
      if (msg.includes('No device selected')) msg = null; // User cancelled picker

      setErrorMsg(msg || "连接失败");
    } finally {
      setConnecting(false);
    }
  };

  const handleDisconnect = async () => {
    await adbService.disconnect();
    setDevice(null);
    setStackInfo(null);
    setEnvInfo(null);
    setH5Info(null);
    setLogs([]);
  };

  const fetchDeviceData = useCallback(async () => {
    if (!device) return;
    setLoadingData(true);
    try {
        const [stack, env, h5, layoutData] = await Promise.all([
            adbService.getTopActivity(),
            adbService.getEnvironment(),
            adbService.getH5Info(),
            adbService.getLayoutHierarchy()
        ]);
        setStackInfo(stack);
        setEnvInfo(env);
        setH5Info(h5);
        setLayout(layoutData);
    } catch (e) {
        console.error("Error fetching data", e);
    } finally {
        setLoadingData(false);
    }
  }, [device]);

  useEffect(() => {
    if (device) {
      // Initial fetch
      fetchDeviceData();

      // Poll data every 5 seconds
      const poll = setInterval(fetchDeviceData, 5000);

      // Subscribe to logs
      const unsubscribe = adbService.subscribeLogs((log) => {
        setLogs(prev => [log, ...prev].slice(0, 100)); // Keep last 100 logs
      });

      return () => {
        clearInterval(poll);
        unsubscribe();
      };
    }
  }, [device, fetchDeviceData]);

  return (
    <div className="min-h-screen bg-slate-950 text-slate-200 flex flex-col font-sans">
      {/* Header */}
      <header className="h-16 bg-slate-900 border-b border-slate-800 flex items-center justify-between px-6 z-10 shrink-0">
        <div className="flex items-center gap-3">
          <div className="w-8 h-8 rounded-lg bg-cyan-500/10 flex items-center justify-center border border-cyan-500/20">
            <Cpu size={20} className="text-cyan-400" />
          </div>
          <h1 className="text-lg font-bold tracking-tight text-white">Droid<span className="text-cyan-400">Scope</span></h1>
        </div>

        <div className="flex items-center gap-4">
            {errorMsg && (
                <div className="text-xs text-red-300 bg-red-950/40 px-3 py-1.5 rounded border border-red-900/50 flex items-start gap-2 max-w-lg">
                    <AlertCircle size={14} className="shrink-0 mt-0.5" />
                    <span className="whitespace-pre-wrap">{errorMsg}</span>
                    {errorMsg.includes('驱动') && (
                        <a href="https://zadig.akeo.ie/" target="_blank" className="underline font-bold ml-1 hover:text-white whitespace-nowrap">下载 Zadig</a>
                    )}
                </div>
            )}
          {device ? (
            <div className="flex items-center gap-4 bg-slate-800/50 px-4 py-1.5 rounded-full border border-slate-700">
              <div className="flex flex-col items-end leading-none">
                <span className="text-xs font-medium text-slate-200">{device.name}</span>
                <span className="text-[10px] text-green-400 uppercase tracking-wider">{device.status === 'connected' ? '已连接' : '未连接'}</span>
              </div>
              <button 
                onClick={handleDisconnect}
                className="p-1 hover:bg-slate-700 rounded-full transition-colors text-slate-400 hover:text-red-400"
              >
                <AlertCircle size={16} />
              </button>
            </div>
          ) : (
            <button 
              onClick={handleConnect}
              disabled={connecting}
              className="flex items-center gap-2 bg-cyan-600 hover:bg-cyan-500 text-white px-4 py-2 rounded-lg text-sm font-medium transition-colors shadow-lg shadow-cyan-900/20 disabled:opacity-50"
            >
              {connecting ? <RefreshCw className="animate-spin" size={16} /> : <Usb size={16} />}
              {connecting ? '正在连接...' : '连接 USB 设备'}
            </button>
          )}
        </div>
      </header>

      {/* Main Content */}
      <main className="flex-1 p-6 grid grid-cols-1 lg:grid-cols-12 gap-6">

        {/* Left Column: Screen Mirror */}
        <div className="lg:col-span-4 flex flex-col min-h-[500px]">
           <ScreenMirror connected={!!device} />
        </div>

        {/* Right Column: Information Grid */}
        <div className="lg:col-span-8 flex flex-col gap-6">

          {/* Top Row: Info Panels */}
          <div className="grid grid-cols-1 md:grid-cols-3 gap-6 shrink-0 h-64">

            <InfoPanel title="顶层 Activity" icon={Layers} loading={loadingData}>
              {device && !isAppOpen ? (
                <div className="h-full flex flex-col items-center justify-center text-slate-600 text-center px-4">
                    <Layers size={24} className="mb-2 opacity-30" />
                    <span className="text-xs">无 App 打开</span>
                    <span className="text-[10px] mt-1 opacity-50">(当前位于桌面或锁屏)</span>
                </div>
              ) : stackInfo ? (
                <div className="space-y-4">
                  <div>
                    <span className="text-[10px] uppercase text-slate-500 font-bold tracking-wider">Activity 类名</span>
                    <p className="text-sm font-mono text-cyan-300 break-all">{stackInfo.activityName.split('.').pop()}</p>
                  </div>
                  <div>
                    <span className="text-[10px] uppercase text-slate-500 font-bold tracking-wider">包名</span>
                    <p className="text-xs text-slate-400 break-all">{stackInfo.packageName}</p>
                  </div>
                  <div className="flex gap-2">
                     <span className={`text-[10px] px-2 py-0.5 rounded border ${stackInfo.isRunning ? 'border-green-800 bg-green-900/30 text-green-400' : 'border-red-800 bg-red-900/30 text-red-400'}`}>
                       {stackInfo.isRunning ? '前台运行' : '已暂停'}
                     </span>
                     <span className="text-[10px] px-2 py-0.5 rounded border border-slate-700 bg-slate-800 text-slate-400">
                       任务 ID: {stackInfo.taskId}
                     </span>
                  </div>
                </div>
              ) : (
                <div className="h-full flex flex-col items-center justify-center text-slate-600 text-center px-4">
                    <Layers size={24} className="mb-2 opacity-30" />
                    <span className="text-xs">
                        {device ? "正在获取栈信息..." : "连接设备以查看"}
                    </span>
                </div>
              )}
            </InfoPanel>

            <InfoPanel title="环境信息" icon={Box} loading={loadingData}>
              {envInfo ? (
                <div className="space-y-4">
                  <div className="flex flex-col items-center justify-center py-2">
                    <span className={`text-xl font-black tracking-widest ${
                      envInfo.environment === 'PRODUCTION' 
                        ? 'text-red-400 drop-shadow-[0_0_8px_rgba(248,113,113,0.3)]' 
                        : envInfo.environment === 'STAGING'
                        ? 'text-yellow-400 drop-shadow-[0_0_8px_rgba(250,204,21,0.3)]'
                        : 'text-green-400'
                    }`}>
                      {envInfo.environment}
                    </span>
                  </div>
                  <div className="grid grid-cols-2 gap-2 text-xs">
                    <div className="bg-slate-950 p-2 rounded border border-slate-800">
                      <span className="block text-[10px] text-slate-500">版本号</span>
                      <span className="text-slate-300 font-mono">{envInfo.versionName}</span>
                    </div>
                    <div className="bg-slate-950 p-2 rounded border border-slate-800">
                      <span className="block text-[10px] text-slate-500">构建号</span>
                      <span className="text-slate-300 font-mono">{envInfo.versionCode}</span>
                    </div>
                  </div>
                </div>
              ) : (
                <div className="h-full flex flex-col items-center justify-center text-slate-600 text-center px-4">
                   <Box size={24} className="mb-2 opacity-30" />
                   <span className="text-xs">
                       {device ? "正在获取属性..." : "连接设备以查看"}
                   </span>
                </div>
              )}
            </InfoPanel>

            <InfoPanel title="WebView H5 调试" icon={Globe} loading={loadingData}>
               {h5Info && h5Info.currentUrl ? (
                <div className="space-y-3">
                  <div>
                    <span className="text-[10px] uppercase text-slate-500 font-bold tracking-wider">页面标题</span>
                    <p className="text-sm font-medium text-slate-200 line-clamp-1">{h5Info.pageTitle}</p>
                  </div>
                  <div>
                    <span className="text-[10px] uppercase text-slate-500 font-bold tracking-wider">当前 URL</span>
                    <div className="p-2 bg-slate-950 rounded border border-slate-800 mt-1">
                      <p className="text-xs font-mono text-cyan-300 break-all line-clamp-3 leading-relaxed">
                        {h5Info.currentUrl}
                      </p>
                    </div>
                  </div>
                  <a 
                    href={h5Info.currentUrl} 
                    target="_blank" 
                    rel="noopener noreferrer"
                    className="text-[10px] text-cyan-500 hover:text-cyan-400 hover:underline flex items-center gap-1 justify-end"
                  >
                    在浏览器中打开 &rarr;
                  </a>
                </div>
               ) : (
                <div className="h-full flex flex-col items-center justify-center text-slate-600 text-center px-4">
                   <Globe size={24} className="mb-2 opacity-30" />
                   <span className="text-xs">未检测到 WebView</span>
                </div>
               )}
            </InfoPanel>

          </div>

          {/* Bottom Row: Tabs (Layout / Logs / Tools) */}
          <div className="h-[600px] bg-slate-900 rounded-xl border border-slate-800 shadow-md flex flex-col">
            <div className="flex border-b border-slate-800 px-2">
