declare global {
  interface Window {
    Adb: any;
  }
  interface Navigator {
    usb: any;
  }
}

class AdbService {
  private adb: any = null; // The Adb Client instance
  private webusb: any = null; // The WebUSB transport layer
  private connected: boolean = false;
  private isRecording: boolean = false;

  isSupported(): boolean {
    return !!navigator.usb; 
  }

  // Poll for the global Adb object to be ready
  private async waitForSDK(): Promise<void> {
    if (window.Adb) return;

    // Check every 100ms for up to 3 seconds
    for (let i = 0; i < 30; i++) {
        if (window.Adb) return;
        await new Promise(resolve => setTimeout(resolve, 100));
    }
    throw new Error("WebADB SDK 加载失败，请检查网络连接 (jsdelivr CDN)");
  }

  // Simulate 'adb devices' logic using WebUSB API
  // This lists devices that the user has previously granted permission to access via WebUSB.
  async getPairedDevices(): Promise<any[]> {
    if (!navigator.usb) return [];
    try {
        const devices = await navigator.usb.getDevices();
        return devices;
    } catch (e) {
        console.warn("Could not get devices", e);
        return [];
    }
  }

  async connect(): Promise<DeviceInfo> {
    // 1. Check for WebUSB support
    if (!navigator.usb) {
      throw new Error("浏览器不支持 WebUSB。请使用 Chrome/Edge，并确保通过 HTTPS 或 localhost 访问。");
    }

    // 2. Wait for library
    await this.waitForSDK();

    try {
      // 3. Initialize Transport Layer
      if (typeof window.Adb.open !== 'function') {
          throw new Error("WebADB 库版本不兼容 (缺少 open 方法)");
      }

      // 4. Open Connection
      // This will trigger the browser device picker.
      this.webusb = await window.Adb.open("WebUSB");

      // Delay: Give the hardware interface a moment to settle.
      await new Promise(resolve => setTimeout(resolve, 500));

      // 5. Handshake (Adb Connect)
      try {
          // host:: tells ADB to connect as a host
          this.adb = await this.webusb.connectAdb("host::");
      } catch (handshakeErr: any) {
          console.error("Handshake failed:", handshakeErr);
          // If the native ADB server is running, it might partially accept connection or corrupt the stream,
          // causing the handshake to fail weirdly.
          throw new Error(`CONFLICT:${handshakeErr.message}`);
      }

      this.connected = true;

      // Use the raw USB device object from the transport layer for metadata
      const rawDevice = this.webusb.device; 

      const deviceName = rawDevice?.productName || "Android Device";
      const manufacturer = rawDevice?.manufacturerName || "Google";
      const serial = rawDevice?.serialNumber || "usb-device";

      return {
        id: serial,
        name: deviceName,
        model: manufacturer,
        status: 'connected',
        batteryLevel: await this.getBatteryLevel()
      };
    } catch (e: any) {
      console.error("ADB Connect Logic Error:", e);
      this.cleanup();

      const isConflict = e.message?.includes('ClaimInterface') || 
                         e.message?.includes('Device is busy') ||
                         e.message?.includes('CONFLICT');

      // --- CRITICAL CONFLICT CHECK ---
      if (isConflict) {
          throw new Error(
              "⚠️ 冲突检测：USB 接口被占用。\n\n" +
              "浏览器无法与正在运行的本地 ADB 服务共存。\n" +
              "既然您在终端能看到设备，请务必执行以下命令杀掉本地服务：\n\n" +
              ">  adb kill-server\n\n" +
              "执行后，请不要在终端运行任何 adb 命令，直接点击下方的重试。"
          );
      }

      // 1. Check if user cancelled or no device selected
      if (e.name === 'NotFoundError' || e.message?.includes('No device selected')) {
          const paired = await this.getPairedDevices();
          if (paired.length === 0) {
               throw new Error("未检测到设备。\n请检查：\n1. USB 线是否连接良好\n2. Windows 用户是否安装了 Zadig 驱动");
          } else {
               throw new Error("操作已取消。");
          }
      }

      // 2. Check for Permission Denied (Driver)
      if (e.name === 'SecurityError' || e.message?.includes('Access denied')) {
          throw new Error("访问被拒绝 (SecurityError)。\n请确保没有任何其他程序（如 Android Studio、手机助手）正在使用该设备。");
      }

      // 3. Fallback Handshake Failure
      if (e.message?.includes('HANDSHAKE_FAILED') || e.message?.includes('closed') || e.message?.includes('auth')) {
          throw new Error(
            `ADB 握手失败。\n\n如果您确认终端能连接，请务必先运行 'adb kill-server'。\n如果不行，请尝试在开发者选项中“撤销 USB 调试授权”并重插。`
          );
      }

      throw new Error(e.message || "连接建立失败");
    }
  }

  private cleanup() {
      this.connected = false;
      this.adb = null;
      this.webusb = null;
  }

  async disconnect(): Promise<void> {
    if (this.adb) {
      try {
        await this.adb.close(); // Close ADB session
      } catch (e) { /* ignore */ }
    }
    if (this.webusb) {
        try {
            // WebADB doesn't always expose close on transport, but we can try
            if (this.webusb.device && this.webusb.device.close) {
                await this.webusb.device.close();
            }
        } catch (e) { /* ignore */ }
    }
    this.cleanup();
  }

  // --- Real ADB Commands ---

  async sendKeyEvent(keyCode: number): Promise<void> {
    if (!this.connected || !this.adb) return;
    try {
        await this.adb.shell(`input keyevent ${keyCode}`);
    } catch (e) { console.warn("Key event failed", e); }
  }

  async tap(x: number, y: number): Promise<void> {
    if (!this.connected || !this.adb) return;
    await this.adb.shell(`input tap ${x} ${y}`);
  }

  async swipe(x1: number, y1: number, x2: number, y2: number, duration: number): Promise<void> {
    if (!this.connected || !this.adb) return;
    await this.adb.shell(`input swipe ${x1} ${y1} ${x2} ${y2} ${duration}`);
  }

  async terminateApp(packageName: string): Promise<void> {
    if (!this.connected || !this.adb) return;
    await this.adb.shell(`am force-stop ${packageName}`);
  }

  // --- Data Fetchers ---

  async getBatteryLevel(): Promise<number> {
      try {
          const output = await this.execShell('dumpsys battery | grep level');
          const match = output.match(/level:\s*(\d+)/);
          return match ? parseInt(match[1], 10) : 50;
      } catch (e) {
          return 50;
      }
  }

  async getTopActivity(): Promise<AppStackInfo | null> {
    if (!this.connected || !this.adb) return null;
    try {
        const output = await this.execShell('dumpsys activity activities | grep -E "mResumedActivity|mFocusedActivity" | tail -n 1');
        const match = output.match(/u0\s+([^\s\/]+)\/([^\s\}]+)/);

        if (match) {
            let pkg = match[1];
            let activity = match[2];
            if (activity.startsWith('.')) activity = pkg + activity;

            return {
                packageName: pkg,
                activityName: activity,
                taskId: 0,
                isRunning: true
            };
        }
        return {
             packageName: 'System',
             activityName: 'Launcher/Unknown',
             taskId: 0,
             isRunning: true
        };
    } catch (e) {
        return null;
    }
  }

  async getEnvironment(): Promise<AppEnvInfo | null> {
     if (!this.connected || !this.adb) return null;
     try {
         const ver = await this.execShell('getprop ro.build.version.release');
         const sdk = await this.execShell('getprop ro.build.version.sdk');
         return {
            environment: 'DEVELOPMENT',
            versionCode: parseInt(sdk.trim()),
            versionName: `Android ${ver.trim()}`,
            debuggable: true
         };
     } catch (e) {
         return null;
     }
  }

  async getH5Info(): Promise<H5Info | null> {
    if (!this.connected) return null;
    return {
      currentUrl: null,
      pageTitle: null,
      userAgent: ""
    };
  }

  async getLayoutHierarchy(): Promise<LayoutNode | null> {
    return null;
  }

  subscribeLogs(callback: (log: LogEntry) => void): () => void {
    if (!this.connected || !this.adb) return () => {};

    const i = setInterval(() => {
        this.execShell('logcat -d -t 50 -v threadtime *:I').then(output => {
            if (!output) return;
            const lines = output.split('\n');
            lines.forEach(line => {
                if(line.length < 20) return;
                const parts = line.split(/\s+/);
                if (parts.length > 5) {
                    const levelChar = parts[4]; 

                    if (['V','D','I','W','E','A','F'].includes(levelChar)) {
                        let level = LogLevel.INFO;
                        if (levelChar === 'E' || levelChar === 'F') level = LogLevel.ERROR;
                        if (levelChar === 'W') level = LogLevel.WARN;
                        if (levelChar === 'D') level = LogLevel.DEBUG;

                        const tagIndex = 5;
                        const messageIndex = 6;

                        callback({
                            timestamp: parts[1] || '',
                            level: level,
                            tag: parts[tagIndex]?.replace(':', '') || 'System',
                            message: parts.slice(messageIndex).join(' ')
                        });
                    }
                }
            });
        }).catch(() => {});
    }, 2000);

    return () => clearInterval(i);
  }

  async captureScreen(): Promise<string> {
    if (!this.connected || !this.adb) throw new Error("Device disconnected");

    try {
        const frame = await this.adb.framebuffer(); // WebADB uses 'framebuffer()' not screencap typically
        // frame is likely a Canvas or similar in WebADB js implementation, or raw bytes?
        // Let's check the library. Standard webadb.js returns a 'FrameBuffer' object which has toCanvas().

        if (frame && frame.toCanvas) {
            const canvas = frame.toCanvas();
            return canvas.toDataURL('image/png');
        } 

        // Fallback if the library version has screencap helper
        if (this.adb.screencap) {
             const blob = await this.adb.screencap();
             return URL.createObjectURL(blob);
        }

        throw new Error("Screenshot not supported by this ADB version");

    } catch (e) {
        console.error("Capture failed:", e);
        // Fallback to shell screencap (slow but reliable)
        try {
            // This is complex in browser without binary handling helper, skipping deep implementation
            throw e;
        } catch (e2) {
             throw e;
        }
    }
  }

  async toggleScreenRecording(): Promise<boolean> {
      this.isRecording = !this.isRecording;
      return this.isRecording;
  }

  private async execShell(command: string): Promise<string> {
      if (!this.adb) return "";
      try {
          // adb.shell returns a stream in webadb.js usually.
          // We need to read all output.
          // Or, some versions have shell(cmd) that returns string?
          // The standard one returns a stream. Let's handle it.

          const stream = await this.adb.shell(command);
          // Simple reader
          let output = '';
          const reader = stream.getReader ? stream.getReader() : null; // WebADB streams might be different

          // Actually, webadb.js shell() usually returns a custom Stream object, not WhatWG stream
          // It has on('data', ...)

          return new Promise((resolve) => {
              let buf = '';
              stream.on('data', (data: Uint8Array) => {
                   // Convert Uint8Array to string
                   const str = new TextDecoder("utf-8").decode(data);
                   buf += str;
              });
              stream.on('end', () => resolve(buf));
              stream.on('close', () => resolve(buf)); // fallback
          });

      } catch (e) {
          console.warn(`CMD Failed: ${command}`, e);
          return "";
      }
  }

  async toggleLayoutBounds(): Promise<boolean> { 
      const current = await this.execShell('getprop debug.layout');
      const next = current.trim() === 'true' ? 'false' : 'true';
      await this.execShell(`setprop debug.layout ${next}`);
      await this.execShell('service call activity 1599295570');
      return next === 'true';
  }

  async toggleShowTaps(): Promise<boolean> { 
       const current = await this.execShell('settings get system show_touches');
       const next = current.trim() === '1' ? '0' : '1';
       await this.execShell(`settings put system show_touches ${next}`);
       return next === '1';
  }

  async clearAppData(pkg: string): Promise<void> {
      await this.execShell(`pm clear ${pkg}`);
  }

  async restartApp(pkg: string): Promise<void> {
      await this.terminateApp(pkg);
      await this.execShell(`monkey -p ${pkg} -c android.intent.category.LAUNCHER 1`);
  }
}

