        // Let's check the library. Standard webadb.js returns a 'FrameBuffer' object which has toCanvas().

        if (frame && frame.toCanvas) {
            const canvas = frame.toCanvas();
            return canvas.toDataURL('image/png');
        } 

        // Fallback if the library version has screencap helper
        if (this.adb.screencap) {
             const blob = await this.adb.screencap();
             return URL.createObjectURL(blob);
        }

        throw new Error("Screenshot not supported by this ADB version");

    } catch (e) {
        console.error("Capture failed:", e);
        // Fallback to shell screencap (slow but reliable)
        try {
            // This is complex in browser without binary handling helper, skipping deep implementation
            throw e;
        } catch (e2) {
             throw e;
        }
    }
  }

  async toggleScreenRecording(): Promise<boolean> {
      this.isRecording = !this.isRecording;
      return this.isRecording;
  }

  private async execShell(command: string): Promise<string> {
      if (!this.adb) return "";
      try {
          // adb.shell returns a stream in webadb.js usually.
          // We need to read all output.
          // Or, some versions have shell(cmd) that returns string?
          // The standard one returns a stream. Let's handle it.

          const stream = await this.adb.shell(command);
          // Simple reader
          let output = '';
          const reader = stream.getReader ? stream.getReader() : null; // WebADB streams might be different

          // Actually, webadb.js shell() usually returns a custom Stream object, not WhatWG stream
          // It has on('data', ...)

          return new Promise((resolve) => {
              let buf = '';
              stream.on('data', (data: Uint8Array) => {
                   // Convert Uint8Array to string
                   const str = new TextDecoder("utf-8").decode(data);
                   buf += str;
              });
              stream.on('end', () => resolve(buf));
              stream.on('close', () => resolve(buf)); // fallback
          });

      } catch (e) {
          console.warn(`CMD Failed: ${command}`, e);
          return "";
      }
  }

  async toggleLayoutBounds(): Promise<boolean> { 
      const current = await this.execShell('getprop debug.layout');
      const next = current.trim() === 'true' ? 'false' : 'true';
      await this.execShell(`setprop debug.layout ${next}`);
      await this.execShell('service call activity 1599295570');
      return next === 'true';
  }

  async toggleShowTaps(): Promise<boolean> { 
       const current = await this.execShell('settings get system show_touches');
       const next = current.trim() === '1' ? '0' : '1';
       await this.execShell(`settings put system show_touches ${next}`);
       return next === '1';
  }

  async clearAppData(pkg: string): Promise<void> {
      await this.execShell(`pm clear ${pkg}`);
  }

  async restartApp(pkg: string): Promise<void> {
      await this.terminateApp(pkg);
      await this.execShell(`monkey -p ${pkg} -c android.intent.category.LAUNCHER 1`);
  }
}

